import { NextRequest, NextResponse } from "next/server";
import { query } from "@/lib/db";
import { ensureOwnershipColumns, getRequestUser, getScopeUserIds } from "@/lib/requestAuth";

export async function GET(request: NextRequest) {
  try {
    await ensureOwnershipColumns();
    const user = await getRequestUser(request);
    if (!user) {
      return NextResponse.json({ error: 'Non authentifi├®' }, { status: 401 });
    }

    const scopeIds = await getScopeUserIds(user);
    const isAdmin = user.role === 'admin';

    const actionsScope = isAdmin
      ? '(user_id = ANY($1) OR user_id IS NULL)'
      : 'user_id = ANY($1)';
    const campaignsScope = isAdmin
      ? '(user_id = ANY($1) OR user_id IS NULL)'
      : 'user_id = ANY($1)';

    const [actionsResult, followupsResult, statsResult, campaignsResult, toolStepsResult] = await Promise.all([
      query(
        `SELECT
          id,
          action_type,
          target_url,
          target_name,
          payload,
          status,
          result,
          error_message,
          campaign_id,
          prospect_id,
          created_at,
          executed_at
         FROM linkedin_actions_queue
         WHERE ${actionsScope}
         ORDER BY created_at DESC
         LIMIT 40`,
        [scopeIds]
      ).catch((e) => { console.error("[activity] actionsResult error:", e); return { rows: [] }; }),
      query(
        `SELECT
          sf.id,
          sf.prospect_id,
          sf.campaign_id,
          sf.message_text,
          sf.scheduled_for,
          sf.status,
          sf.created_at,
          p.name as prospect_name,
          c.name as campaign_name
         FROM scheduled_followups sf
         LEFT JOIN prospects p ON sf.prospect_id = p.id
         LEFT JOIN campaigns c ON sf.campaign_id = c.id
         WHERE sf.campaign_id IS NULL OR ${campaignsScope.replace('user_id', 'c.user_id')}
         ORDER BY sf.created_at DESC
         LIMIT 20`,
        [scopeIds]
      ).catch((e) => { console.error("[activity] followupsResult error:", e); return { rows: [] }; }),
      query(
        `SELECT
          COALESCE(COUNT(*) FILTER (WHERE status = 'pending_approval'), 0) as pending_approval,
          COALESCE(COUNT(*) FILTER (WHERE status = 'approved'), 0) as approved,
          COALESCE(COUNT(*) FILTER (WHERE status = 'completed'), 0) as completed,
          COALESCE(COUNT(*) FILTER (WHERE status = 'failed'), 0) as failed,
          COALESCE(COUNT(*) FILTER (WHERE status = 'rejected'), 0) as rejected,
          COALESCE(COUNT(*), 0) as total_actions
         FROM linkedin_actions_queue
         WHERE ${actionsScope}`,
        [scopeIds]
      ).catch((e) => { console.error("[activity] statsResult error:", e); return { rows: [] }; }),
      query(
        `SELECT
          id,
          name,
          description,
          status,
          industry,
          location,
          target_role,
          contacted,
          replied,
          created_at,
          updated_at
         FROM campaigns
         WHERE ${campaignsScope}
         ORDER BY created_at DESC
         LIMIT 20`,
        [scopeIds]
      ).catch((e) => { console.error("[activity] campaignsResult error:", e); return { rows: [] }; }),
      query(
        `SELECT id, conversation_id, tool_name, args, result, status, created_at
         FROM agent_tool_steps
         WHERE conversation_id IN (
           SELECT DISTINCT conversation_id FROM agent_chat_history WHERE ${actionsScope}
         )
         ORDER BY created_at DESC
         LIMIT 50`,
        [scopeIds]
      ).catch((e) => { console.error("[activity] toolStepsResult error:", e); return { rows: [] }; }),
    ]);

    const actionItems = actionsResult.rows.map((row) => ({
      id: `action-${row.id}`,
      itemType: "linkedin_action",
      actionId: row.id,
      actionType: row.action_type,
      title: getActionTitle(row.action_type),
      description: buildActionDescription(row),
      detail: buildActionDetail(row),
      status: row.status,
      statusLabel: getStatusLabel(row.status),
      targetName: row.target_name,
      targetUrl: row.target_url,
      campaignId: row.campaign_id,
      prospectId: row.prospect_id,
      payload: row.payload,
      result: row.result,
      errorMessage: row.error_message,
      createdAt: row.created_at,
      executedAt: row.executed_at,
      priority: getPriority(row.status),
    }));

    const followupItems = followupsResult.rows.map((row) => ({
      id: `followup-${row.id}`,
      itemType: "followup",
      actionId: row.id,
      actionType: "scheduled_followup",
      title: "Relance planifi├®e",
      description: row.prospect_name
        ? `Relance programm├®e pour ${row.prospect_name}`
        : "Relance automatique programm├®e",
      detail: row.message_text,
      status: row.status,
      statusLabel: getStatusLabel(row.status),
      targetName: row.prospect_name,
      targetUrl: null,
      campaignId: row.campaign_id,
      prospectId: row.prospect_id,
      payload: { scheduled_for: row.scheduled_for, campaign_name: row.campaign_name },
      result: null,
      errorMessage: null,
      createdAt: row.created_at,
      executedAt: row.scheduled_for,
      priority: row.status === "scheduled" ? "medium" : "low",
    }));

    const campaignItems = campaignsResult.rows.map((row) => ({
      id: `campaign-${row.id}`,
      itemType: "campaign" as const,
      actionId: row.id,
      actionType: "create_campaign",
      title: `Campagne: ${row.name}`,
      description: buildCampaignDescription(row),
      detail: buildCampaignDetail(row),
      status: row.status || "draft",
      statusLabel: getCampaignStatusLabel(row.status),
      targetName: row.target_role || null,
      targetUrl: null,
      campaignId: row.id,
      prospectId: null,
      payload: { industry: row.industry, location: row.location },
      result: { contacted: row.contacted, replied: row.replied },
      errorMessage: null,
      createdAt: row.created_at,
      executedAt: row.updated_at,
      priority: row.status === "active" ? "high" as const : "medium" as const,
    }));

    const toolStepItems = toolStepsResult.rows.map((row: any) => {
      const args = typeof row.args === "string" ? JSON.parse(row.args) : row.args;
      return {
        id: `step-${row.id}`,
        itemType: "tool_step" as const,
        actionId: row.id,
        actionType: row.tool_name,
        title: getToolStepTitle(row.tool_name),
        description: getToolStepDescription(row.tool_name, args, row.status),
        detail: buildToolStepDetail(row.tool_name, args, row.result),
        status: row.status === "success" ? "success" : "failed",
        statusLabel: row.status === "success" ? "Succ├¿s" : "Erreur",
        targetName: args?.prospect_name || args?.name || null,
        targetUrl: args?.linkedin_url || args?.url || null,
        campaignId: args?.campaign_id || null,
        prospectId: null,
        payload: args,
        result: row.result,
        errorMessage: row.status === "error" ? row.result : null,
        createdAt: row.created_at,
        executedAt: row.created_at,
        priority: "medium" as const,
      };
    });

    const timeline = [...actionItems, ...followupItems, ...campaignItems, ...toolStepItems]
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      .slice(0, 50);

    const stats = statsResult.rows[0] || {
      pending_approval: 0,
      approved: 0,
      completed: 0,
      failed: 0,
      rejected: 0,
      total_actions: 0,
    };

    return NextResponse.json({
      success: true,
      timeline,
      stats: {
        pendingApproval: Number(stats.pending_approval || 0),
        approved: Number(stats.approved || 0),
        completed: Number(stats.completed || 0),
        failed: Number(stats.failed || 0),
        rejected: Number(stats.rejected || 0),
        totalActions: Number(stats.total_actions || 0),
        scheduledFollowups: followupItems.filter((item) => item.status === "scheduled").length,
      },
    });
  } catch (error) {
    console.error("Agent activity API error:", error);
    return NextResponse.json(
      { success: false, error: "Erreur lors de la r├®cup├®ration de l'activit├® de l'agent" },
      { status: 500 }
    );
  }
}

function getActionTitle(actionType: string) {
  const titles: Record<string, string> = {
    search: "Recherche LinkedIn",
    search_and_message: "Recherche et Envoi de message",
    visit_profile: "Analyse de profil",
    send_connection: "Demande de connexion",
    send_message: "Envoi de message",
    scheduled_followup: "Relance planifi├®e",
  };

  return titles[actionType] || actionType;
}

function getStatusLabel(status: string) {
  const labels: Record<string, string> = {
    pending: "En attente",
    pending_approval: "En attente",
    approved: "Approuv├®e",
    processing: "En cours",
    completed: "Termin├®e",
    failed: "├ëchou├®e",
    stopped: "Arr├¬t├®e",
    rejected: "Rejet├®e",
    scheduled: "Planifi├®e",
    sent: "Envoy├®e",
    cancelled: "Annul├®e",
  };

  return labels[status] || status;
}

function getPriority(status: string) {
  if (status === "pending_approval" || status === "failed") return "high";
  if (status === "approved" || status === "processing" || status === "scheduled") return "medium";
  return "low";
}

function buildActionDescription(row: any) {
  return null;
}

function buildActionDetail(row: any) {
  const payload = normalizeJson(row.payload);
  const result = normalizeJson(row.result);
  const details: string[] = [];

  if (payload?.keywords) details.push(`Recherche: ${payload.keywords}`);
  if (payload?.limit) details.push(`Limite: ${payload.limit}`);
  if (row.target_name) details.push(`Cible: ${row.target_name}`);
  if (payload?.note) details.push(`Note: ${payload.note}`);
  if (payload?.message) details.push(`Message: ${payload.message}`);
  if (payload?.message_template) details.push(`Message: ${payload.message_template}`);
  if (result?.profile?.company) details.push(`Entreprise: ${result.profile.company}`);
  if (result?.messages_sent !== undefined) details.push(`Messages envoy├®s: ${result.messages_sent}`);
  if (result?.profiles_found !== undefined) details.push(`Profils trouv├®s: ${result.profiles_found}`);

  return details.join("\n") || null;
}

function buildCampaignDescription(row: any) {
  if (row.status === "active") {
    return `Campagne active avec ${row.contacted || 0} prospects contact├®s et ${row.replied || 0} r├®ponses.`;
  }
  if (row.status === "paused") {
    return `Campagne en pause. Vous pouvez la r├®activer via l'agent ou la page Campagnes.`;
  }
  if (row.status === "completed") {
    return `Campagne termin├®e. ${row.contacted || 0} prospects contact├®s, ${row.replied || 0} r├®ponses re├ºues.`;
  }
  return `Campagne cr├®├®e par l'agent et en attente d'activation. Demandez ├á l'agent de l'activer ou utilisez la page Campagnes.`;
}

function buildCampaignDetail(row: any) {
  const details: string[] = [];
  if (row.description) details.push(row.description);
  if (row.industry) details.push(`Secteur: ${row.industry}`);
  if (row.location) details.push(`Zone: ${row.location}`);
  if (row.target_role) details.push(`Cible: ${row.target_role}`);
  return details.join(" ÔÇó ") || "Aucun d├®tail compl├®mentaire.";
}

function getCampaignStatusLabel(status: string) {
  const labels: Record<string, string> = {
    draft: "Brouillon",
    active: "Active",
    paused: "En pause",
    completed: "Termin├®e",
  };
  return labels[status] || status;
}

function getToolStepTitle(toolName: string) {
  const titles: Record<string, string> = {
    create_campaign: "├ëtape: Cr├®ation de campagne",
    update_campaign: "├ëtape: Mise ├á jour campagne",
    linkedin_search: "├ëtape: Recherche LinkedIn",
    linkedin_visit_profile: "├ëtape: Visite de profil",
    linkedin_send_connection: "├ëtape: Demande de connexion",
    linkedin_send_message: "├ëtape: Envoi de message",
    analyze_prospect: "├ëtape: Analyse de prospect",
    generate_message: "├ëtape: G├®n├®ration de message",
    suggest_strategy: "├ëtape: Suggestion de strat├®gie",
    search_prospects_db: "├ëtape: Analyse de la liste de prospects",
    check_network_connections: "├ëtape: V├®rification des connexions r├®seau",
    get_connection_results: "├ëtape: R├®sultats des connexions r├®seau",
    save_prospect: "├ëtape: Sauvegarde prospect",
    get_campaign_stats: "├ëtape: Stats campagne",
    schedule_followup: "├ëtape: Planification relance",
    get_rate_limits: "├ëtape: V├®rification limites",
  };
  return titles[toolName] || `├ëtape: ${toolName}`;
}

function getToolStepDescription(toolName: string, args: any, status: string) {
  const statusText = status === "success" ? "r├®ussie" : "├®chou├®e";
  if (toolName === "create_campaign") return `Cr├®ation de la campagne "${args?.name || ""}" ÔÇö ${statusText}`;
  if (toolName === "linkedin_search") return `Recherche: "${args?.keywords || ""}" ÔÇö ${statusText}`;
  if (toolName === "linkedin_send_connection") return `Connexion ├á ${args?.prospect_name || args?.linkedin_url || "prospect"} ÔÇö ${statusText}`;
  if (toolName === "linkedin_send_message") return `Message ├á ${args?.prospect_name || "prospect"} ÔÇö ${statusText}`;
  if (toolName === "analyze_prospect") return `Analyse du profil ${args?.linkedin_url || ""} ÔÇö ${statusText}`;
  if (toolName === "generate_message") return `R├®daction d'un message ${args?.message_type || ""} ÔÇö ${statusText}`;
  if (toolName === "suggest_strategy") return `├ëlaboration d'une strat├®gie de prospection ÔÇö ${statusText}`;
  if (toolName === "save_prospect") return `Sauvegarde de ${args?.name || "prospect"} en base ÔÇö ${statusText}`;
  if (toolName === "search_prospects_db") return `Analyse de la liste de prospects en base de donn├®es ÔÇö ${statusText}`;
  if (toolName === "check_network_connections") {
    const names = args?.prospect_names;
    const count = Array.isArray(names) ? names.length : "?";
    return `V├®rification r├®seau lanc├®e pour ${count} prospect(s) via l'extension Chrome ÔÇö ${statusText}`;
  }
  if (toolName === "get_connection_results") return `R├®cup├®ration des r├®sultats de connexion LinkedIn ÔÇö ${statusText}`;
  if (toolName === "get_campaign_stats") return `R├®cup├®ration des statistiques ÔÇö ${statusText}`;
  if (toolName === "schedule_followup") return `Planification d'une relance ÔÇö ${statusText}`;
  return `Ex├®cution de ${toolName} ÔÇö ${statusText}`;
}

function buildToolStepDetail(toolName: string, args: any, result: string) {
  const details: string[] = [];
  if (args) {
    for (const [key, value] of Object.entries(args)) {
      if (value && typeof value === "string" && value.length < 200) {
        details.push(`${key}: ${value}`);
      }
    }
  }
  // Try to extract a summary from the result
  try {
    const parsed = JSON.parse(result);
    if (toolName === "check_network_connections" && parsed.summary) {
      details.push(parsed.summary);
    } else if (parsed.message) {
      details.push(`R├®sultat: ${parsed.message}`);
    } else if (parsed.summary) {
      details.push(parsed.summary);
    } else if (parsed.success !== undefined) {
      details.push(`Succ├¿s: ${parsed.success ? "Oui" : "Non"}`);
    }
  } catch {
    if (result && result.length < 300) details.push(`R├®sultat: ${result.substring(0, 200)}`);
  }
  return details.join(" ÔÇó ") || "├ëtape interm├®diaire de l'agent.";
}

function normalizeJson(value: unknown) {
  if (!value) return null;
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch {
      return null;
    }
  }
  return value as Record<string, unknown>;
}

import { NextRequest, NextResponse } from "next/server";
import { query } from "@/lib/db";
import { z } from "zod";
import { ensureOwnershipColumns, getRequestUser, getScopeUserIds } from "@/lib/requestAuth";

// Schema validation pour mise ├á jour
const campaignUpdateSchema = z.object({
  name: z.string().min(1).optional(),
  description: z.string().optional(),
  industry: z.string().optional(),
  location: z.string().optional(),
  company_size: z.string().optional(),
  target_role: z.string().optional(),
  target: z.string().optional(),
  template: z.string().optional(),
  template_invitation: z.string().optional(),
  template_followup: z.string().optional(),
  status: z.enum(["draft", "active", "paused", "completed"]).optional(),
  contacted: z.number().optional(),
  replied: z.number().optional(),
  converted: z.number().optional(),
  connections_sent: z.number().optional(),
  connections_accepted: z.number().optional(),
  objective: z.string().optional(),
  seniority: z.string().optional(),
  campaign_type: z.string().optional(),
  daily_limit: z.number().optional(),
  follow_up_days: z.number().optional(),
});

// V├®rifie que le requester peut acc├®der ├á la campagne (sinon retourne null)
async function assertAccess(request: NextRequest, campaignId: number) {
  await ensureOwnershipColumns();
  const user = await getRequestUser(request);
  if (!user) return { ok: false as const, status: 401, error: "Non authentifi├®" };

  const owner = await query("SELECT user_id FROM campaigns WHERE id = $1", [campaignId]);
  if (owner.rows.length === 0) return { ok: false as const, status: 404, error: "Campagne non trouv├®e" };

  const ownerId: number | null = owner.rows[0].user_id;
  const scopeIds = await getScopeUserIds(user);
  const allowed = ownerId == null ? user.role === "admin" : scopeIds.includes(ownerId);
  if (!allowed) return { ok: false as const, status: 403, error: "Acc├¿s refus├®" };

  return { ok: true as const, user };
}

// GET /api/campaigns/[id]
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: idStr } = await params;
    const id = parseInt(idStr);
    if (isNaN(id)) {
      return NextResponse.json({ error: "ID invalide" }, { status: 400 });
    }

    const access = await assertAccess(request, id);
    if (!access.ok) {
      return NextResponse.json({ error: access.error }, { status: access.status });
    }

    const result = await query(
      `SELECT c.*,
        COALESCE(json_agg(
          json_build_object(
            'id', m.id,
            'prospect_id', m.prospect_id,
            'recipient_name', m.recipient_name,
            'recipient_role', m.recipient_role,
            'recipient_company', m.recipient_company,
            'message_text', m.message_text,
            'status', m.status,
            'message_type', m.message_type,
            'created_at', m.created_at
          ) ORDER BY m.created_at DESC
        ) FILTER (WHERE m.id IS NOT NULL), '[]') as messages
      FROM campaigns c
      LEFT JOIN messages m ON c.id = m.campaign_id
      WHERE c.id = $1
      GROUP BY c.id`,
      [id]
    );

    if (result.rows.length === 0) {
      return NextResponse.json({ error: "Campagne non trouv├®e" }, { status: 404 });
    }

    return NextResponse.json({ success: true, campaign: result.rows[0] });
  } catch (error) {
    console.error("GET /api/campaigns/[id] error:", error);
    return NextResponse.json(
      { error: "Erreur lors de la r├®cup├®ration de la campagne" },
      { status: 500 }
    );
  }
}

// PUT /api/campaigns/[id]
export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: idStr } = await params;
    const id = parseInt(idStr);
    if (isNaN(id)) {
      return NextResponse.json({ error: "ID invalide" }, { status: 400 });
    }

    const access = await assertAccess(request, id);
    if (!access.ok) {
      return NextResponse.json({ error: access.error }, { status: access.status });
    }

    const body = await request.json();
    const validated = campaignUpdateSchema.parse(body);

    const updates: string[] = [];
    const values: any[] = [];
    let paramCount = 0;

    Object.entries(validated).forEach(([key, value]) => {
      if (value !== undefined) {
        paramCount++;
        updates.push(`${key} = $${paramCount}`);
        values.push(value);
      }
    });

    if (updates.length === 0) {
      return NextResponse.json({ error: "Aucune donn├®e ├á mettre ├á jour" }, { status: 400 });
    }

    paramCount++;
    updates.push(`updated_at = NOW()`);
    values.push(id);

    const sql = `UPDATE campaigns SET ${updates.join(", ")} WHERE id = $${paramCount} RETURNING *`;
    const result = await query(sql, values);

    if (result.rows.length === 0) {
      return NextResponse.json({ error: "Campagne non trouv├®e" }, { status: 404 });
    }

    return NextResponse.json({ success: true, campaign: result.rows[0] });
  } catch (error) {
    console.error("PUT /api/campaigns/[id] error:", error);
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: "Donn├®es invalides", details: error.format() },
        { status: 400 }
      );
    }
    return NextResponse.json(
      { error: "Erreur lors de la mise ├á jour de la campagne" },
      { status: 500 }
    );
  }
}

// DELETE /api/campaigns/[id]
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: idStr } = await params;
    const id = parseInt(idStr);
    if (isNaN(id)) {
      return NextResponse.json({ error: "ID invalide" }, { status: 400 });
    }

    const access = await assertAccess(request, id);
    if (!access.ok) {
      return NextResponse.json({ error: access.error }, { status: access.status });
    }

    await query("DELETE FROM messages WHERE campaign_id = $1", [id]);
    const result = await query("DELETE FROM campaigns WHERE id = $1 RETURNING id", [id]);

    if (result.rows.length === 0) {
      return NextResponse.json({ error: "Campagne non trouv├®e" }, { status: 404 });
    }

    return NextResponse.json({ success: true, message: "Campagne supprim├®e avec succ├¿s" });
  } catch (error) {
    console.error("DELETE /api/campaigns/[id] error:", error);
    return NextResponse.json(
      { error: "Erreur lors de la suppression de la campagne" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { query } from '@/lib/db';

// GET /api/debug/actions - V├®rifier l'├®tat des actions r├®centes (debug uniquement)
export async function GET(request: NextRequest) {
  try {
    const result = await query(
      `SELECT q.*, c.name as campaign_name, c.status as campaign_status
       FROM linkedin_actions_queue q
       LEFT JOIN campaigns c ON c.id = q.campaign_id
       ORDER BY q.created_at DESC
       LIMIT 10`
    );

    return NextResponse.json({
      success: true,
      actions: result.rows,
    });
  } catch (error) {
    console.error('Error fetching debug actions:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch actions' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { pool } from "@/lib/db";

// OPTIONS ÔÇö CORS preflight
export async function OPTIONS() {
  return new NextResponse(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, POST, DELETE, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type, Authorization",
    },
  });
}

