import { NextResponse } from "next/server";
import { pool } from "@/lib/db";
import { logger } from "@/lib/logger";
import { perfMonitor } from "@/lib/performance-monitor";
import { cache } from "@/lib/cache";

// =============================================
// Real-Time Monitoring Endpoint
// Vue agr├®g├®e de l'├®tat de tout le syst├¿me
// =============================================

const startTime = Date.now();

export async function GET() {
  const data: Record<string, any> = {
    timestamp: new Date().toISOString(),
    uptime: Math.floor((Date.now() - startTime) / 1000),
  };

  // 1. System health
  data.system = {
    nodeVersion: process.version,
    platform: process.platform,
    memory: {
      rss: Math.round(process.memoryUsage().rss / 1024 / 1024) + " MB",
      heapUsed: Math.round(process.memoryUsage().heapUsed / 1024 / 1024) + " MB",
      heapTotal: Math.round(process.memoryUsage().heapTotal / 1024 / 1024) + " MB",
    },
    instance: process.env.HOSTNAME || "local",
  };

  // 2. Database stats
  try {
    const dbStart = performance.now();
    const [actionsResult, prospectsResult, campaignsResult, recentActions] = await Promise.all([
      pool.query(`SELECT status, COUNT(*) as count FROM linkedin_actions_queue GROUP BY status`),
      pool.query(`SELECT status, COUNT(*) as count FROM prospects GROUP BY status`),
      pool.query(`SELECT status, COUNT(*) as count FROM campaigns GROUP BY status`),
      pool.query(
        `SELECT action_type, status, COUNT(*) as count
         FROM linkedin_actions_queue
         WHERE created_at > NOW() - INTERVAL '1 hour'
         GROUP BY action_type, status`
      ),
    ]);

    data.database = {
      latency: Number((performance.now() - dbStart).toFixed(2)),
      pool: {
        total: pool.totalCount,
        idle: pool.idleCount,
        waiting: pool.waitingCount,
      },
      actions: Object.fromEntries(actionsResult.rows.map((r) => [r.status, parseInt(r.count)])),
      prospects: Object.fromEntries(prospectsResult.rows.map((r) => [r.status, parseInt(r.count)])),
      campaigns: Object.fromEntries(campaignsResult.rows.map((r) => [r.status, parseInt(r.count)])),
      lastHour: recentActions.rows,
    };
  } catch (e) {
    data.database = { error: e instanceof Error ? e.message : String(e) };
  }

  // 3. Performance metrics
  data.performance = {
    api: perfMonitor.getStatsByOperation(),
    cache: cache.getStats(),
  };

  // 4. Logs r├®cents
  data.logs = {
    stats: logger.getStats(),
    recentErrors: logger.getRecent(10, "warn"),
  };

  // 5. Extension connectivity (bas├® sur l'activit├® r├®cente)
  try {
    const extensionActivity = await pool.query(
      `SELECT MAX(executed_at) as last_action,
              COUNT(*) FILTER (WHERE executed_at > NOW() - INTERVAL '5 minutes') as recent_actions
       FROM linkedin_actions_queue
       WHERE status = 'completed'`
    );
    const row = extensionActivity.rows[0];
    const lastAction = row.last_action ? new Date(row.last_action) : null;
    const minutesSinceLast = lastAction
      ? Math.floor((Date.now() - lastAction.getTime()) / 60000)
      : null;

    data.extension = {
      status: minutesSinceLast !== null && minutesSinceLast < 15 ? "connected" : "idle",
      lastAction: lastAction?.toISOString() || null,
      minutesSinceLast,
      recentActions: parseInt(row.recent_actions || "0"),
    };
  } catch (e) {
    data.extension = { error: "unavailable" };
  }

  return NextResponse.json({ success: true, ...data });
}

import { NextRequest, NextResponse } from 'next/server';
import { query } from '@/lib/db';
import { getRequestUser, getScopeUserIds } from '@/lib/requestAuth';

// GET /api/notifications - Get notifications and stats (scoped by user)
export async function GET(request: NextRequest) {
  try {
    const user = await getRequestUser(request);
    const isAdmin = user?.role === 'admin';
    const scopeIds = user ? await getScopeUserIds(user) : [];

    const scopeClause = isAdmin
      ? '(user_id = ANY($1) OR user_id IS NULL)'
      : 'user_id = ANY($1)';

    // Get unread count (scoped)
    const unreadResult = await query(
      `SELECT COUNT(*) as count FROM notifications WHERE read = false AND ${scopeClause}`,
      [scopeIds]
    );

    // Get total notifications with limit (scoped)
    const notificationsResult = await query(
      `SELECT * FROM notifications
       WHERE ${scopeClause}
       ORDER BY created_at DESC
       LIMIT 50`,
      [scopeIds]
    );

    // Get online prospects (last seen within 5 minutes)
    const onlineResult = await query(
      `SELECT COUNT(*) as count FROM prospects 
       WHERE last_seen > NOW() - INTERVAL '5 minutes'`
    );

    // Get new replies count (messages with status replied, converted from last 24h)
    const newRepliesResult = await query(
      `SELECT COUNT(*) as count FROM messages 
       WHERE status IN ('replied', 'converted') 
       AND created_at > NOW() - INTERVAL '24 hours'`
    );

    return NextResponse.json({
      success: true,
      unread: parseInt(unreadResult.rows[0]?.count || '0'),
      online: parseInt(onlineResult.rows[0]?.count || '0'),
      newReplies: parseInt(newRepliesResult.rows[0]?.count || '0'),
      notifications: notificationsResult.rows
    });
  } catch (error) {
    console.error('Error fetching notifications:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch notifications', unread: 0, online: 0, newReplies: 0, notifications: [] },
      { status: 500 }
    );
  }
}

// POST /api/notifications - Create a notification
export async function POST(request: NextRequest) {
  try {
    const user = await getRequestUser(request);
    const body = await request.json();
    const { type, title, message, data } = body;

    const result = await query(
      `INSERT INTO notifications (type, title, message, data, user_id)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING *`,
      [type, title, message, JSON.stringify(data || {}), user?.userId ?? null]
    );

    return NextResponse.json({
      success: true,
      notification: result.rows[0]
    });
  } catch (error) {
    console.error('Error creating notification:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to create notification' },
      { status: 500 }
    );
  }
}

// DELETE /api/notifications - Delete all notifications for current user
export async function DELETE(request: NextRequest) {
  try {
    const user = await getRequestUser(request);
    if (!user) {
      return NextResponse.json({ error: 'Non authentifi├®' }, { status: 401 });
    }
    const isAdmin = user.role === 'admin';
    if (isAdmin) {
      await query(`DELETE FROM notifications`);
    } else {
      await query(`DELETE FROM notifications WHERE user_id = $1`, [user.userId]);
    }
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error deleting notifications:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete notifications' },
      { status: 500 }
    );
  }
}

// PATCH /api/notifications - Mark as read
export async function PATCH(request: NextRequest) {
  try {
    let body: any = {};
    try {
      body = await request.json();
    } catch {
      // no body = mark all as read
    }
    const { id, read } = body;

    const user = await getRequestUser(request);
    const isAdmin = user?.role === 'admin';
    const scopeIds = user ? await getScopeUserIds(user) : [];
    const scopeClause = isAdmin
      ? '(user_id = ANY($1) OR user_id IS NULL)'
      : 'user_id = ANY($1)';

    if (id) {
      // Mark specific notification as read (only if belongs to user)
      await query(
        `UPDATE notifications SET read = $1 WHERE id = $2 AND ${scopeClause}`,
        [read ?? true, id, scopeIds]
      );
    } else {
      // Mark all as read (scoped)
      await query(`UPDATE notifications SET read = true WHERE ${scopeClause}`, [scopeIds]);
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error updating notification:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to update notification' },
      { status: 500 }
    );
  }
}

