import { NextRequest, NextResponse } from "next/server";
import { query } from "@/lib/db";
import { verifyToken } from "@/lib/auth";
import { z } from "zod";

const userSchema = z.object({
  name: z.string().min(1, "Nom requis"),
  email: z.string().email("Email invalide"),
  company: z.string().optional(),
  role: z.string().optional(),
  linkedin_connected: z.boolean().default(false),
  linkedin_email: z.string().email().optional().or(z.literal("")),
  settings: z.record(z.string(), z.unknown()).optional(),
});

async function resolveCurrentUser(request: NextRequest) {
  // 1. Essayer JWT (users secondaires)
  const authHeader = request.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const payload = await verifyToken(authHeader.slice(7));
    if (payload) {
      const result = await query(
        "SELECT * FROM users WHERE id = $1",
        [payload.userId]
      );
      if (result.rows.length > 0) return result.rows[0];
    }
  }

  // 2. Essayer LinkedIn auth (admins)
  const adminResult = await query(
    `SELECT u.* FROM users u
     JOIN app_settings s ON s.key = 'linkedin_session_cookie'
     WHERE u.role = 'admin'
     LIMIT 1`
  );
  if (adminResult.rows.length > 0) return adminResult.rows[0];

  // 3. Legacy fallback
  const legacy = await query("SELECT * FROM users LIMIT 1");
  if (legacy.rows.length > 0) return legacy.rows[0];

  return null;
}

// GET /api/users/me - R├®cup├®rer l'utilisateur courant (admin via LinkedIn, user via JWT)
export async function GET(request: NextRequest) {
  try {
    const user = await resolveCurrentUser(request);

    if (!user) {
      return NextResponse.json(
        { success: false, user: null },
        { status: 401 }
      );
    }

    return NextResponse.json({
      success: true,
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        company: user.company,
        role: user.role || "admin",
        linkedin_connected: user.linkedin_connected,
        linkedin_email: user.linkedin_email,
        settings: user.settings,
        admin_id: user.admin_id,
        is_active: user.is_active,
      },
    });
  } catch (error) {
    console.error("GET /api/users/me error:", error);
    return NextResponse.json(
      { error: "Erreur lors de la r├®cup├®ration de l'utilisateur" },
      { status: 500 }
    );
  }
}

// PUT /api/users/me - Mettre ├á jour le profil courant
export async function PUT(request: NextRequest) {
  try {
    const currentUser = await resolveCurrentUser(request);
    if (!currentUser) {
      return NextResponse.json(
        { error: "Non authentifi├®" },
        { status: 401 }
      );
    }

    const body = await request.json();
    const validated = userSchema.partial().parse(body);

    const updates: string[] = [];
    const values: any[] = [];
    let paramCount = 0;

    Object.entries(validated).forEach(([key, value]) => {
      if (value !== undefined) {
        paramCount++;
        if (key === "settings") {
          updates.push(`${key} = COALESCE(${key}, '{}'::jsonb) || $${paramCount}::jsonb`);
        } else {
          updates.push(`${key} = $${paramCount}`);
        }
        values.push(key === "settings" ? JSON.stringify(value) : value);
      }
    });

    if (updates.length === 0) {
      return NextResponse.json({ error: "Aucune donn├®e ├á mettre ├á jour" }, { status: 400 });
    }

    paramCount++;
    updates.push(`updated_at = NOW()`);
    values.push(currentUser.id);

    const sql = `UPDATE users SET ${updates.join(", ")} WHERE id = $${paramCount} RETURNING *`;
    const result = await query(sql, values);

    return NextResponse.json({
      success: true,
      user: result.rows[0],
    });
  } catch (error) {
    console.error("PUT /api/users/me error:", error);
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: "Donn├®es invalides", details: error.format() },
        { status: 400 }
      );
    }
    return NextResponse.json(
      { error: "Erreur lors de la mise ├á jour" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { query } from "@/lib/db";
import { verifyToken, isAdmin, hashPassword } from "@/lib/auth";

// Auto-migration : s'assure que les colonnes auth existent
async function ensureAuthColumns() {
  await query(`ALTER TABLE users ADD COLUMN IF NOT EXISTS password_hash TEXT`);
  await query(`ALTER TABLE users ADD COLUMN IF NOT EXISTS admin_id INTEGER REFERENCES users(id) ON DELETE SET NULL`);
  await query(`ALTER TABLE users ADD COLUMN IF NOT EXISTS is_active BOOLEAN NOT NULL DEFAULT TRUE`);
}

// Helper : extraire l'admin authentifi├®
async function getAuthenticatedAdmin(request: NextRequest) {
  // JWT d'abord
  const authHeader = request.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const payload = await verifyToken(authHeader.slice(7));
    if (payload && isAdmin(payload.role)) {
      return payload;
    }
  }
  // LinkedIn auth (cookie session)
  const result = await query(
    "SELECT id FROM users WHERE role = 'admin' LIMIT 1"
  );
  if (result.rows.length > 0) {
    return { userId: result.rows[0].id, role: "admin" };
  }
  return null;
}

