export default function AgentChat() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [timeline, setTimeline] = useState<ActivityItem[]>([]);
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [conversationId, setConversationId] = useState<string | null>(null);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isBootstrapping, setIsBootstrapping] = useState(true);
  const [isActivityLoading, setIsActivityLoading] = useState(true);
  const [rightPanelView, setRightPanelView] = useState<"actions" | "history">("actions");
  const [deleteTarget, setDeleteTarget] = useState<{ id: string; preview: string } | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Scroll automatique vers le bas
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Focus automatique sur l'input
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  // Charger les conversations depuis l'API
  const refreshConversations = async () => {
    try {
      const response = await fetch("/api/agent/chat");
      const data = await response.json();
      if (data.success && data.conversations) {
        setConversations(data.conversations);
      }
    } catch (error) {
      console.error("Erreur chargement conversations:", error);
    }
  };

  // Charger une conversation sp├®cifique
  const loadConversation = async (convId: string) => {
    try {
      const response = await fetch(`/api/agent/chat?conversationId=${convId}`);
      const data = await response.json();
      if (data.success && data.history?.length) {
        setConversationId(convId);
        setMessages(
          data.history.map((msg: Message) => ({
            ...msg,
            timestamp: String(msg.timestamp),
          }))
        );
      }
    } catch (error) {
      console.error("Erreur chargement conversation:", error);
    }
  };

  useEffect(() => {
    async function bootstrap() {
      try {
        const [historyResponse, activityResponse] = await Promise.all([
          fetch("/api/agent/chat"),
          fetch("/api/agent/activity"),
        ]);

        const historyData = await historyResponse.json();
        const activityData = await activityResponse.json();

        if (historyData.success) {
          if (historyData.conversations?.length) {
            setConversations(historyData.conversations);
          }
          // Load the latest conversation if available
          const latestConv = historyData.conversations?.[0];
          if (latestConv) {
            setConversationId(latestConv.id);
            // Load messages for that conversation
            const convResponse = await fetch(`/api/agent/chat?conversationId=${latestConv.id}`);
            const convData = await convResponse.json();
            if (convData.success && convData.history?.length) {
              setMessages(
                convData.history.map((message: Message) => ({
                  ...message,
                  timestamp: String(message.timestamp),
                }))
              );
            } else {
              setMessages([welcomeMessage]);
            }
          } else {
            setMessages([welcomeMessage]);
          }
        } else {
          setMessages([welcomeMessage]);
        }

        if (activityData.success) {
          setTimeline(activityData.timeline || []);
        }
      } catch (error) {
        console.error("Erreur lors du chargement de l'espace agent:", error);
        setMessages([welcomeMessage]);
      } finally {
        setIsBootstrapping(false);
        setIsActivityLoading(false);
      }
    }

    bootstrap();
  }, []);

  useEffect(() => {
    const interval = window.setInterval(async () => {
      try {
        const response = await fetch("/api/agent/activity");
        const data = await response.json();
        if (data.success) {
          setTimeline(data.timeline || []);
        }
      } catch (error) {
        console.error("Erreur lors du rafra├«chissement des actions:", error);
      }
    }, 4000);

    return () => window.clearInterval(interval);
  }, []);

  const rapidPollRef = useRef<NodeJS.Timeout | null>(null);
  const startRapidPolling = () => {
    if (rapidPollRef.current) clearInterval(rapidPollRef.current);
    let count = 0;
    rapidPollRef.current = setInterval(async () => {
      count++;
      await refreshActivity();
      if (count >= 15) {
        if (rapidPollRef.current) clearInterval(rapidPollRef.current);
        rapidPollRef.current = null;
      }
    }, 2000);
  };
  useEffect(() => {
    return () => { if (rapidPollRef.current) clearInterval(rapidPollRef.current); };
  }, []);

  const refreshActivity = async () => {
    setIsActivityLoading(true);
    try {
      const response = await fetch("/api/agent/activity");
      const data = await response.json();
      if (data.success) {
        setTimeline(data.timeline || []);
      }
    } catch (error) {
      console.error("Erreur lors de l'actualisation des actions:", error);
    } finally {
      setIsActivityLoading(false);
    }
  };

  // Envoyer un message
  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content: input,
      timestamp: new Date().toISOString(),
    };

    setMessages((prev) => prev.filter((m) => m.id !== "welcome").concat(userMessage));
    setInput("");
    setIsLoading(true);

    // Message temporaire de l'assistant (loading)
    const loadingId = (Date.now() + 1).toString();
    setMessages((prev) => [
      ...prev,
      { id: loadingId, role: "assistant", content: "", timestamp: new Date().toISOString(), isLoading: true },
    ]);

    try {
      const response = await fetch("/api/agent/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: userMessage.content,
          conversationId: conversationId || undefined,
          context: {
            currentPage: window.location.pathname,
            timestamp: new Date().toISOString(),
          },
        }),
      });

      const data = await response.json();

      if (!response.ok && !data.response) {
        throw new Error("Agent request failed");
      }

      // Save the conversationId returned by the API
      if (data.conversationId && !conversationId) {
        setConversationId(data.conversationId);
      }

      // Remplacer le message loading par la vraie r├®ponse
      setMessages((prev) =>
        prev.map((msg) =>
          msg.id === loadingId
            ? {
                id: loadingId,
                role: "assistant",
                content: data.response || "Je n'ai pas pu terminer cette demande pour le moment.",
                timestamp: new Date().toISOString(),
                isLoading: false,
              }
            : msg
        )
      );

      refreshActivity();
      refreshConversations();
    } catch (error) {
      setMessages((prev) => prev.filter((msg) => msg.id !== loadingId));
    } finally {
      setIsLoading(false);
    }
  };

  // Nouvelle conversation (trash icon)
  const handleNewConversation = async () => {
    try {
      await fetch("/api/agent/chat", { method: "DELETE" });
      setConversationId(null);
      setMessages([welcomeMessage]);
      refreshConversations();
    } catch (error) {
      console.error("Erreur lors de la cr├®ation:", error);
    }
  };

  // Ouvrir le modal de confirmation de suppression
  const askDeleteConversation = (convId: string, preview: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setDeleteTarget({ id: convId, preview: preview.substring(0, 60) + (preview.length > 60 ? "..." : "") });
  };

  // Confirmer la suppression d├®finitive
  const confirmDelete = async () => {
    if (!deleteTarget) return;
    setIsDeleting(true);
    try {
      const res = await fetch(`/api/agent/chat?conversationId=${deleteTarget.id}`, { method: "DELETE" });
      const data = await res.json();
      if (data.success) {
        if (deleteTarget.id === conversationId) {
          setConversationId(null);
          setMessages([welcomeMessage]);
        }
        refreshConversations();
      }
    } catch (error) {
      console.error("Erreur suppression conversation:", error);
    } finally {
      setIsDeleting(false);
      setDeleteTarget(null);
    }
  };

  // Suggestions rapides
  const suggestions = [
    { icon: Target, text: "Cr├®er une campagne" },
    { icon: MessageSquare, text: "R├®diger un message" },
    { icon: TrendingUp, text: "Analyser mes stats" },
  ];

  const [processingActionId, setProcessingActionId] = useState<number | null>(null);

  // --- Action management (approve / reject / retry) ---
  const updateAction = async (actionId: number, action: "approve" | "reject" | "retry" | "stop" | "continue") => {
    const numericId = Number(actionId);
    if (!numericId || isNaN(numericId)) {
      console.error("[AgentChat] Invalid actionId:", actionId);
      return;
    }
    setProcessingActionId(numericId);
    try {
      const response = await fetch("/api/linkedin-actions/approval", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: numericId, action }),
      });
      const data = await response.json();
      if (data.success) {
        await refreshActivity();
        if (action === "approve" || action === "retry" || action === "stop" || action === "continue") {
          startRapidPolling();
        }
      } else {
        console.error(`[AgentChat] Action ${action} failed:`, data.error);
      }
    } catch (error) {
      console.error(`[AgentChat] Error trying to ${action} action:`, error);
    } finally {
      setProcessingActionId(null);
    }
  };

  // Deduplicate: keep only linkedin_action items; remove tool_steps that duplicate them
  const actionItems = (() => {
    const linkedinActionIds = new Set(
      timeline
        .filter((t) => t.itemType === "linkedin_action")
        .map((t) => t.actionId)
    );

    // For tool_steps related to linkedin actions (linkedin_search, linkedin_send_message, etc.)
    // only keep them if no linkedin_action with the same actionId exists
    const toolStepNames = new Set([
      "linkedin_search", "linkedin_send_message", "linkedin_visit_profile",
      "linkedin_send_connection", "check_network_connections", "get_connection_results",
    ]);

    return timeline.filter((item) => {
      if (item.itemType === "tool_step" && toolStepNames.has(item.actionType)) {
        return false; // hide tool steps that correspond to real queued actions
      }
      return true;
    });
  })();

  return (
    <div className="h-full w-full flex flex-col">
      <div className="flex-1 min-h-0 grid grid-cols-1 xl:grid-cols-[1fr_420px] overflow-hidden">
        <Card className="flex flex-col min-h-0 m-5 rounded-2xl border border-slate-200/60 bg-gradient-to-br from-white via-slate-50/50 to-blue-50/30 shadow-[0_20px_50px_-12px_rgba(0,0,0,0.15),0_0_0_1px_rgba(255,255,255,0.5)_inset,0_-2px_0_0_rgba(255,255,255,0.8)_inset] overflow-hidden">
          <CardHeader className="shrink-0 border-b border-slate-200/80 bg-white px-5 h-[76px] flex flex-row items-center justify-between space-y-0">
            <div className="flex items-center gap-3">
                <div className="w-11 h-11 rounded-2xl bg-[#CDDFF2] flex items-center justify-center">
                  <Bot className="w-6 h-6 text-blue-900" />
                </div>
                <div>
                  <CardTitle className="text-xl font-bold text-slate-900 flex items-center gap-1.5">
                    Agent Linkedin
                  </CardTitle>
                  <p className="text-xs text-slate-500">Conversation pilot├®e par OpenAI et l'extension Chrome</p>
                </div>
              </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleNewConversation}
              className="text-rose-500 hover:text-rose-600 shrink-0"
            >
              <Trash2 className="w-4 h-4" />
            </Button>
          </CardHeader>

          <CardContent className="flex flex-1 min-h-0 flex-col p-0 overflow-hidden">
            <div className="flex-1 overflow-y-auto px-5 py-4">
              {isBootstrapping ? (
                <div className="flex h-full items-center justify-center text-slate-500">
                  <div className="flex items-center gap-3 rounded-2xl border border-slate-200 bg-white px-4 py-3 shadow-sm">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Chargement de la conversation...
                  </div>
                </div>
              ) : (
                <>
                  <AnimatePresence>
                    {messages.map((message) => (
                      <motion.div
                        key={message.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.25 }}
                        className={cn(
                          "mb-4 flex gap-3",
                          message.role === "user" ? "flex-row-reverse" : "flex-row"
                        )}
                      >
                        <div
                          className={cn(
                            "mt-1 flex h-9 w-9 shrink-0 items-center justify-center rounded-2xl shadow-sm",
                            message.role === "user"
                              ? "bg-gradient-to-br from-blue-500 to-blue-600"
                              : "bg-[#CDDFF2]"
                          )}
                        >
                          {message.role === "user" ? (
                            <User className="w-4 h-4 text-white" />
                          ) : (
                            <Bot className="w-4 h-4 text-blue-900" />
                          )}
                        </div>

                        <div className={cn("max-w-[88%]", message.role === "user" ? "items-end" : "items-start")}>
                          <div
                            className={cn(
                              "rounded-3xl px-4 py-3 text-sm shadow-sm border",
                              message.role === "user"
                                ? "bg-blue-600 text-white border-blue-600 rounded-br-lg"
                                : "bg-white text-slate-900 border-slate-200 rounded-bl-lg"
                            )}
                          >
                            {message.isLoading ? (
                              <div className="flex items-center gap-2">
                                <Loader2 className="w-4 h-4 animate-spin" />
                                <span className={cn(message.role === "user" ? "text-white/90" : "text-slate-500")}>
                                  L'agent r├®fl├®chit et pr├®pare les actions...
                                </span>
                              </div>
                            ) : (
                              <div className="whitespace-pre-wrap leading-6">{message.content}</div>
                            )}
                          </div>
                          <p className={cn("mt-1 px-2 text-[11px] text-slate-400", message.role === "user" ? "text-right" : "text-left")}>
                            {formatDateLabel(message.timestamp)}
                          </p>
                        </div>
                      </motion.div>
                    ))}
                  </AnimatePresence>

                  <div ref={messagesEndRef} />

                  {messages.length <= 1 && (
                    <div className="mt-3 flex flex-wrap gap-2">
                      {suggestions.map((suggestion) => (
                        <button
                          key={suggestion.text}
                          onClick={() => {
                            setInput(suggestion.text);
                            inputRef.current?.focus();
                          }}
                          className="flex items-center gap-2 rounded-full border border-blue-100 bg-blue-50 px-3.5 py-2 text-xs font-medium text-blue-700 transition-colors hover:bg-blue-100"
                        >
                          <suggestion.icon className="w-3.5 h-3.5" />
                          {suggestion.text}
                        </button>
                      ))}
                    </div>
                  )}
                </>
              )}
            </div>

            <div className="border-t border-slate-100 bg-white px-5 py-4">
              <div className="rounded-3xl border border-slate-200 bg-white p-2 shadow-inner">
                <div className="flex gap-2">
                  <input
                    ref={inputRef}
                    value={input}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => setInput(e.target.value)}
                    onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                      if (e.key === "Enter" && !e.shiftKey) {
                        e.preventDefault();
                        handleSend();
                      }
                    }}
                    placeholder="Cr├®e une action..."
                    className="flex-1 rounded-2xl border-0 bg-transparent px-3 py-3 text-sm text-slate-700 outline-none placeholder:text-slate-400 disabled:cursor-not-allowed disabled:opacity-50"
                    disabled={isLoading}
                  />
                  <button
                    type="button"
                    onClick={handleSend}
                    disabled={!input.trim() || isLoading}
                    className="h-11 rounded-2xl bg-[#CDDFF2] px-4 text-blue-900 hover:bg-[#B8D4EE] disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                  >
                    {isLoading ? (
                      <Loader2 className="w-4 h-4 animate-spin" style={{ color: '#0f172a' }} />
                    ) : (
                      <Send className="w-4 h-4" style={{ color: '#0f172a' }} />
                    )}
                  </button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="flex flex-col min-h-0 border-0 shadow-none bg-gradient-to-br from-slate-50 to-white rounded-none">
          <CardHeader className="shrink-0 border-b border-slate-200/80 px-5 h-[76px] flex flex-row items-center justify-between space-y-0 bg-white">
            <CardTitle className="text-lg font-bold text-slate-900">
              {rightPanelView === "actions" ? "Actions de l'agent" : "Historique des chats"}
            </CardTitle>

              <div className="ml-auto flex items-center gap-1">
                <Button
                  variant={rightPanelView === "actions" ? "default" : "outline"}
                  size="sm"
                  onClick={() => { setRightPanelView("actions"); refreshActivity(); }}
                  className={cn(
                    "text-xs px-2.5",
                    rightPanelView === "actions"
                      ? "bg-blue-600 text-white hover:bg-blue-700"
                      : "border-slate-200 bg-white"
                  )}
                  title="Actions de l'agent"
                >
                  <ClipboardList className="w-3.5 h-3.5 mr-1" />
                  Actions
                </Button>
                <Button
                  variant={rightPanelView === "history" ? "default" : "outline"}
                  size="sm"
                  onClick={() => setRightPanelView("history")}
                  className={cn(
                    "text-xs px-2.5",
                    rightPanelView === "history"
                      ? "bg-violet-600 text-white hover:bg-violet-700"
                      : "border-slate-200 bg-white"
                  )}
                  title="Historique des chats"
                >
                  <MessageSquare className="w-3.5 h-3.5 mr-1" />
                  Chats
                </Button>
              </div>
          </CardHeader>

          <CardContent className="flex flex-1 min-h-0 flex-col p-0 overflow-hidden">
            {rightPanelView === "actions" ? (
              <>
                <div className="flex-1 overflow-y-auto px-4 py-4">
                  {isActivityLoading && actionItems.length === 0 ? (
                    <div className="flex h-full items-center justify-center text-slate-500">
                      <div className="flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-3 shadow-sm">
                        <Loader2 className="w-4 h-4 animate-spin" />
                        Chargement des actions agent...
                      </div>
                    </div>
                  ) : actionItems.length === 0 ? (
                    <div className="flex h-full items-center justify-center">
                      <div className="rounded-3xl border border-dashed border-slate-200 bg-slate-50 px-5 py-6 text-center">
                        <ClipboardList className="mx-auto mb-3 h-8 w-8 text-slate-300" />
                        <p className="text-sm font-semibold text-slate-700">Aucune action agent pour le moment</p>
                        <p className="mt-1 text-xs text-slate-500">D├¿s que l'agent cr├®e une campagne, recherche, connexion ou message, cela appara├«tra ici.</p>
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-3">
                      {actionItems.map((item) => {
                        const Icon = getActivityIcon(item.actionType);
                        const styles = getStatusStyles(item.status);
                        const isProcessing = processingActionId === item.actionId;
                        const isLinkedInAction = item.itemType === "linkedin_action";

                        return (
                          <motion.div
                            key={item.id}
                            initial={{ opacity: 0, x: 12 }}
                            animate={{ opacity: 1, x: 0 }}
                            className={cn("rounded-2xl border bg-white p-4 shadow-sm transition-all hover:shadow-md", styles.border)}
                          >
                            <div className="flex items-start gap-3">
                              <div className={cn("p-2.5 rounded-xl border-0 shadow-sm", getActionBadgeColor(item.status))}>
                                <Icon className="w-5 h-5" />
                              </div>

                              <div className="min-w-0 flex-1">
                                {/* Row 1: Title + Status badge ÔÇö min-h matches icon height */}
                                <div className="flex min-h-10 flex-wrap items-center gap-2">
                                  <h4 className="text-sm font-semibold text-slate-900">{item.itemType === "linkedin_action" ? getActionLabel(item.actionType) : item.title}</h4>
                                  <span className={cn("rounded-full border px-2 py-0.5 text-[10px] font-medium", styles.badge)}>
                                    {item.statusLabel}
                                  </span>
                                </div>

                                {/* Row 2: Action Buttons */}
                                {isLinkedInAction && (
                                  <div className="mt-2 flex items-center gap-1.5" onClick={(e) => e.stopPropagation()}>
                                    {item.status === "pending_approval" && (
                                      <>
                                        <button
                                          type="button"
                                          onClick={(e) => { e.stopPropagation(); updateAction(item.actionId, "approve"); }}
                                          disabled={isProcessing}
                                          className="flex items-center gap-1 px-2.5 py-1 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 text-emerald-700 rounded-lg text-[11px] font-medium transition-colors disabled:opacity-50 cursor-pointer"
                                        >
                                          {isProcessing ? <RefreshCw className="w-3 h-3 animate-spin" /> : <Check className="w-3 h-3" />}
                                          Approuver
                                        </button>
                                        <button
                                          type="button"
                                          onClick={(e) => { e.stopPropagation(); updateAction(item.actionId, "reject"); }}
                                          disabled={isProcessing}
                                          className="flex items-center gap-1 px-2.5 py-1 bg-rose-50 hover:bg-rose-100 border border-rose-200 text-rose-700 rounded-lg text-[11px] font-medium transition-colors disabled:opacity-50 cursor-pointer"
                                        >
                                          <X className="w-3 h-3" />
                                          Rejeter
                                        </button>
                                      </>
                                    )}
                                    {(item.status === "approved" || item.status === "processing") && (
                                      <button
                                        type="button"
                                        onClick={(e) => { e.stopPropagation(); updateAction(item.actionId, "stop"); }}
                                        disabled={isProcessing}
                                        className="flex items-center gap-1 px-2.5 py-1 bg-orange-50 hover:bg-orange-100 border border-orange-200 text-orange-700 rounded-lg text-[11px] font-medium transition-colors disabled:opacity-50 cursor-pointer"
                                      >
                                        {isProcessing ? <RefreshCw className="w-3 h-3 animate-spin" /> : <Square className="w-3 h-3" />}
                                        Stop
                                      </button>
                                    )}
                                    {item.status === "stopped" && (
                                      <button
                                        type="button"
                                        onClick={(e) => { e.stopPropagation(); updateAction(item.actionId, "continue"); }}
                                        disabled={isProcessing}
                                        className="flex items-center gap-1 px-2.5 py-1 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 text-emerald-700 rounded-lg text-[11px] font-medium transition-colors disabled:opacity-50 cursor-pointer"
                                      >
                                        {isProcessing ? <RefreshCw className="w-3 h-3 animate-spin" /> : <Play className="w-3 h-3" />}
                                        Continuer
                                      </button>
                                    )}
                                    {(item.status === "rejected" || item.status === "failed") && (
                                      <button
                                        type="button"
                                        onClick={(e) => { e.stopPropagation(); updateAction(item.actionId, "retry"); }}
                                        disabled={isProcessing}
                                        className="flex items-center gap-1 px-2.5 py-1 bg-violet-50 hover:bg-violet-100 border border-violet-200 text-violet-700 rounded-lg text-[11px] font-medium transition-colors disabled:opacity-50 cursor-pointer"
                                      >
                                        {isProcessing ? <RefreshCw className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                                        R├®essayer
                                      </button>
                                    )}
                                  </div>
                                )}

                                {/* Prospect list link */}
                                {item.targetUrl && (
                                  <a
                                    href={item.targetUrl}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="mt-2 inline-flex items-center gap-1 text-[11px] font-medium text-blue-600 hover:text-blue-800 hover:underline"
                                  >
                                    Voir la liste des prospects
                                    <ExternalLink className="w-3 h-3" />
                                  </a>
                                )}

                                {/* Detail block */}
                                {item.detail && (
                                  <div className="mt-2.5 rounded-xl border border-slate-100 bg-slate-50/70 p-2.5">
                                    <p className="text-[11px] font-medium text-slate-500 mb-1">D├®tail</p>
                                    {item.detail.split("\n").map((line: string, i: number) => (
                                      <p key={i} className="text-xs leading-5 text-slate-600">{line}</p>
                                    ))}
                                  </div>
                                )}

                                {/* Timestamps */}
                                <div className="mt-2.5 flex flex-wrap items-center gap-3 text-[11px] text-slate-500">
                                  <span className="inline-flex items-center gap-1">
                                    <span className={cn("h-1.5 w-1.5 rounded-full", styles.dot)} />
                                    {formatTimeAgo(item.createdAt)}
                                  </span>
                                  {item.targetName && <span>Cible: {item.targetName}</span>}
                                  {item.executedAt && <span>Ex├®cution: {formatDateLabel(item.executedAt)}</span>}
                                </div>

                              </div>
                            </div>
                          </motion.div>
                        );
                      })}
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div className="flex-1 overflow-y-auto px-4 py-4">
                {conversations.length === 0 ? (
                  <div className="flex h-full items-center justify-center">
                    <div className="rounded-3xl border border-dashed border-slate-200 bg-slate-50 px-5 py-6 text-center">
                      <History className="mx-auto mb-3 h-8 w-8 text-slate-300" />
                      <p className="text-sm font-semibold text-slate-700">Aucune conversation</p>
                      <p className="mt-1 text-xs text-slate-500">Vos ├®changes avec l'agent appara├«tront ici.</p>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {conversations.map((conv) => (
                      <motion.button
                        key={conv.id}
                        initial={{ opacity: 0, y: 6 }}
                        animate={{ opacity: 1, y: 0 }}
                        onClick={() => loadConversation(conv.id)}
                        className={cn(
                          "w-full text-left rounded-2xl border p-3.5 shadow-sm transition-all hover:shadow-md cursor-pointer",
                          conv.id === conversationId
                            ? "border-blue-300 bg-blue-50/80 ring-1 ring-blue-200"
                            : "border-slate-200 bg-white hover:border-violet-200 hover:bg-violet-50/30"
                        )}
                      >
                        <div className="flex items-start gap-3">
                          <div className={cn(
                            "mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-xl",
                            conv.id === conversationId
                              ? "bg-blue-500"
                              : "bg-gradient-to-br from-violet-500 to-blue-500"
                          )}>
                            <MessageSquare className="w-4 h-4 text-white" />
                          </div>
                          <div className="min-w-0 flex-1">
                            <p className="text-sm font-medium text-slate-900 line-clamp-2 leading-5">
                              {conv.firstMessage}
                            </p>
                            <div className="mt-1.5 flex items-center gap-2 text-[11px] text-slate-400">
                              <span>{formatDateLabel(conv.startedAt)}</span>
                              <span>ÔÇó</span>
                              <span>{conv.messageCount} msg</span>
                            </div>
                          </div>
                          <div
                            role="button"
                            tabIndex={0}
                            onClick={(e) => askDeleteConversation(conv.id, conv.firstMessage, e)}
                            className="shrink-0 mt-0.5 p-1.5 rounded-lg text-rose-500 hover:text-rose-600 hover:bg-rose-50 transition-colors cursor-pointer"
                            title="Supprimer cette conversation"
                          >
                            <Trash2 className="w-3.5 h-3.5" />
                          </div>
                        </div>
                      </motion.button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Modal de confirmation de suppression */}
      <AnimatePresence>
        {deleteTarget && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[9999] flex items-center justify-center p-4"
            onClick={() => setDeleteTarget(null)}
          >
            <div className="absolute inset-0 bg-black/50" />
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="relative w-full max-w-xs bg-white rounded-2xl shadow-xl overflow-hidden"
              onClick={(e) => e.stopPropagation()}
            >
              {/* Header */}
              <div className="bg-red-50 px-4 py-3">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 bg-red-100 rounded-lg flex items-center justify-center">
                    <Trash2 className="w-4 h-4 text-red-600" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-sm text-gray-900">Supprimer la conversation</h3>
                    <p className="text-xs text-gray-500">{deleteTarget.preview.substring(0, 30)}...</p>
                  </div>
                </div>
              </div>

              {/* Content */}
              <div className="p-4">
                <div className="text-center py-3">
                  <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-2">
                    <Trash2 className="w-6 h-6 text-gray-400" />
                  </div>
                  <p className="text-gray-500 font-medium text-sm">
                    Supprimer cette conversation ?
                  </p>
                  <p className="text-xs text-gray-400 mt-1">
                    Cette action est irr├®versible. La conversation et tous ses messages seront supprim├®s d├®finitivement.
                  </p>
                </div>
              </div>

              {/* Footer */}
              <div className="px-4 py-3 border-t border-gray-100 bg-gray-50 flex gap-2">
                <button
                  onClick={() => setDeleteTarget(null)}
                  disabled={isDeleting}
                  className="flex-1 py-2 text-xs text-gray-600 hover:text-gray-900 font-medium transition-colors disabled:opacity-50"
                >
                  Annuler
                </button>
                <button
                  onClick={confirmDelete}
                  disabled={isDeleting}
                  className="flex-1 py-2 bg-red-600 text-white rounded-lg text-xs font-medium hover:bg-red-700 transition-colors disabled:opacity-50 flex items-center justify-center gap-1"
                >
                  {isDeleting ? (
                    <>
                      <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Suppression...
                    </>
                  ) : (
                    <>
                      <Trash2 className="w-3 h-3" />
                      Supprimer
                    </>
                  )}
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { motion } from "framer-motion";
import {
  Check,
  CheckCircle,
  CheckSquare,
  X,
  Clock,
  Search,
  User,
  MessageSquare,
  Link as LinkIcon,
  UserPlus,
  AlertCircle,
  RefreshCw,
  ExternalLink,
  Square,
  Play,
  Loader2,
  ChevronDown,
  ChevronUp,
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useAuth } from "@/contexts/AuthContext";

interface PendingAction {
  id: number;
  action_type: string;
  target_url: string;
  target_name: string | null;
  payload: any;
  status: string;
  created_at: string;
  error_message?: string | null;
  result?: any;
  user_id?: number | null;
  owner_name?: string | null;
}

interface ActionStats {
  status: string;
  count: number;
}

export default function ApprovalQueue() {
  const { user } = useAuth();
  const [actions, setActions] = useState<PendingAction[]>([]);
  const [allActions, setAllActions] = useState<PendingAction[]>([]);
  const [stats, setStats] = useState<ActionStats[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [processingId, setProcessingId] = useState<number | null>(null);
  const [isRefreshing, setIsRefreshing] = useState<boolean>(false);
  const [selectedStatus, setSelectedStatus] = useState<string | null>("pending_approval");
  const pollingRef = useRef<NodeJS.Timeout | null>(null);
  const [expandedMessageId, setExpandedMessageId] = useState<number | null>(null);

  // --- API helpers ---

  const fetchActionsAndStats = useCallback(async (statusFilter?: string | null) => {
    try {
      setIsRefreshing(true);
      const currentFilter = statusFilter !== undefined ? statusFilter : selectedStatus;

      // Fetch all actions for allActions cache + stats
      const allResponse = await fetch("/api/linkedin-actions/approval");
      const allData = await allResponse.json();

      if (allData.success) {
        setAllActions(allData.actions || []);
        setStats(allData.stats || []);

        // Filtrer les actions affich├®es selon le statut s├®lectionn├®
        const all = allData.actions || [];
        if (currentFilter === null) {
          setActions([...all].sort((a: PendingAction, b: PendingAction) =>
            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
          ));
        } else if (currentFilter === "rejected_failed") {
          setActions(all.filter((a: PendingAction) => a.status === "rejected" || a.status === "failed"));
        } else if (currentFilter === "processing_stopped") {
          setActions(all.filter((a: PendingAction) => a.status === "processing" || a.status === "stopped"));
        } else {
          setActions(all.filter((a: PendingAction) => a.status === currentFilter));
        }
      }
    } catch (error) {
      console.error("Error fetching actions:", error);
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  }, [selectedStatus]);

  const filterByStatus = (status: string | null) => {
    // IMPORTANT: Arr├¬ter le polling en cours pour ├®viter qu'il ├®crase le nouveau filtre
    if (pollingRef.current) {
      clearInterval(pollingRef.current);
      pollingRef.current = null;
    }
    setSelectedStatus(status);
    // Re-fetch avec le nouveau filtre pour avoir des donn├®es fra├«ches
    fetchActionsAndStats(status);
  };

  // D├®marrer un auto-refresh temporaire (ex: apr├¿s une approbation)
  // Le polling utilise toujours le selectedStatus ACTUEL pour ne pas ├®craser le filtre utilisateur
  const startPolling = useCallback(() => {
    if (pollingRef.current) clearInterval(pollingRef.current);
    let count = 0;
    pollingRef.current = setInterval(async () => {
      count++;
      // Utiliser undefined pour que fetchActionsAndStats utilise le selectedStatus actuel
      await fetchActionsAndStats();
      if (count >= 6) {
        // Stop apr├¿s 30s (6 x 5s)
        if (pollingRef.current) clearInterval(pollingRef.current);
        pollingRef.current = null;
      }
    }, 5000);
  }, [fetchActionsAndStats]);

  const updateAction = async (
    id: number,
    action: "approve" | "reject" | "retry" | "stop" | "continue"
  ) => {
    setProcessingId(id);
    try {
      const response = await fetch("/api/linkedin-actions/approval", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id, action }),
      });
      const data = await response.json();
      if (data.success) {
        // Naviguer vers le bon onglet apr├¿s l'action
        let targetStatus: string | null = selectedStatus;
        if (action === "approve") targetStatus = "approved";
        else if (action === "reject") targetStatus = "rejected_failed";
        else if (action === "retry") targetStatus = "pending_approval";
        else if (action === "stop") targetStatus = "processing_stopped";
        else if (action === "continue") targetStatus = "processing_stopped";

        setSelectedStatus(targetStatus);
        await fetchActionsAndStats(targetStatus);

        // D├®marrer un polling temporaire pour suivre l'action
        if (action === "approve" || action === "retry" || action === "continue" || action === "stop") {
          startPolling();
        }
      }
    } catch (error) {
      console.error(`Error trying to ${action} action:`, error);
    } finally {
      setProcessingId(null);
    }
  };

  // Cleanup polling on unmount
  useEffect(() => {
    return () => {
      if (pollingRef.current) clearInterval(pollingRef.current);
    };
  }, []);

  const approveAction = (id: number) => updateAction(id, "approve");
  const rejectAction = (id: number) => updateAction(id, "reject");
  const retryAction = (id: number) => updateAction(id, "retry");
  const stopAction = (id: number) => updateAction(id, "stop");

  useEffect(() => {
    fetchActionsAndStats();
    // Auto-refresh removed - manual refresh only
  }, [fetchActionsAndStats]);

  // --- Helpers UI ---

  const getActionIcon = (type: string) => {
    switch (type) {
      case "search":
        return <Search className="w-5 h-5" />;
      case "search_and_message":
        return <MessageSquare className="w-5 h-5" />;
      case "search_and_connection":
        return <UserPlus className="w-5 h-5" />;
      case "visit_profile":
        return <User className="w-5 h-5" />;
      case "send_connection":
        return <LinkIcon className="w-5 h-5" />;
      case "send_message":
        return <MessageSquare className="w-5 h-5" />;
      case "check_connection":
        return <CheckSquare className="w-5 h-5" />;
      default:
        return <AlertCircle className="w-5 h-5" />;
    }
  };

  const getActionLabel = (type: string) => {
    const labels: Record<string, string> = {
      search: "Recherche LinkedIn",
      search_and_message: "Recherche et Envoi de message",
      search_and_connection: "Recherche et Envoi de connexion",
      visit_profile: "Visiter profil",
      send_connection: "Demande de connexion",
      send_message: "Envoyer un message",
      check_connection: "V├®rification r├®seau",
    };
    return labels[type] || type;
  };

  const getActionBadgeColor = (status: string) => {
    switch (status) {
      case "pending_approval":
        return "bg-yellow-100 text-yellow-700 border-yellow-200";
      case "approved":
        return "bg-green-100 text-green-700 border-green-200";
      case "processing":
        return "bg-indigo-100 text-indigo-700 border-indigo-200";
      case "completed":
        return "bg-blue-100 text-blue-700 border-blue-200";
      case "rejected":
      case "failed":
        return "bg-red-100 text-red-700 border-red-200";
      case "stopped":
        return "bg-orange-100 text-orange-700 border-orange-200";
      case "paused":
        return "bg-amber-100 text-amber-700 border-amber-200";
      default:
        return "bg-gray-100 text-gray-700 border-gray-200";
    }
  };

  const getStatusIconColor = (status: string) => {
    switch (status) {
      case "pending_approval":
        return "text-yellow-600";
      case "approved":
        return "text-green-600";
      case "processing":
        return "text-indigo-600";
      case "completed":
        return "text-blue-600";
      case "rejected":
      case "failed":
        return "text-red-600";
      case "stopped":
        return "text-orange-600";
      case "paused":
        return "text-amber-600";
      default:
        return "text-gray-600";
    }
  };

  const getCount = (status: string): number => {
    const found = stats.find((s) => s.status === status);
    return found ? Number(found.count) : 0;
  };

  const formatPayload = (action: PendingAction) => {
    const payload =
      typeof action.payload === "string"
        ? (() => {
            try {
              return JSON.parse(action.payload);
            } catch {
              return null;
            }
          })()
        : action.payload;

    if (action.action_type === "send_connection" && payload?.note) {
      const text = payload.note as string;
      return `Note : "${text.substring(0, 100)}${
        text.length > 100 ? "..." : ""
      }"`;
    }
    if (action.action_type === "send_message" && payload?.message) {
      const text = payload.message as string;
      return `Message : "${text.substring(0, 100)}${
        text.length > 100 ? "..." : ""
      }"`;
    }
    if (action.action_type === "search" && payload?.keywords) {
      return `Mots-cl├®s : "${payload.keywords}"`;
    }
    if (action.action_type === "search_and_message" && payload?.message_template) {
      const text = payload.message_template as string;
      return `"${text.substring(0, 120)}${text.length > 120 ? "..." : ""}"`;
    }
    return "";
  };

  const totalToday = stats.reduce(
    (acc: number, s: ActionStats) => acc + Number(s.count || 0),
    0
  );

  // Badge de statut pour chaque action
  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending_approval":
        return <Badge className="bg-yellow-100 text-yellow-800 border-yellow-300 text-[10px]">En attente</Badge>;
      case "approved":
        return <Badge className="bg-green-100 text-green-800 border-green-300 text-[10px]">Approuv├®e</Badge>;
      case "processing":
        return <Badge className="bg-indigo-100 text-indigo-800 border-indigo-300 text-[10px]">En cours</Badge>;
      case "completed":
        return <Badge className="bg-blue-100 text-blue-800 border-blue-300 text-[10px]">Termin├®e</Badge>;
      case "rejected":
        return <Badge className="bg-red-100 text-red-800 border-red-300 text-[10px]">Rejet├®e</Badge>;
      case "failed":
        return <Badge className="bg-red-100 text-red-800 border-red-300 text-[10px]">├ëchou├®e</Badge>;
      case "stopped":
        return <Badge className="bg-orange-100 text-orange-800 border-orange-300 text-[10px]">Arr├¬t├®e</Badge>;
      default:
        return <Badge className="bg-gray-100 text-gray-800 text-[10px]">{status}</Badge>;
    }
  };

  // Helper pour afficher les bons boutons selon le statut
  const renderActionButtons = (action: PendingAction) => {
    const isProcessing = processingId === action.id;
    
    switch (action.status) {
      case "pending_approval":
        return (
          <>
            <Button
              size="sm"
              onClick={() => approveAction(action.id)}
              disabled={isProcessing}
              className="bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 text-emerald-700 h-8 px-2.5 text-xs font-medium shadow-none"
            >
              {isProcessing ? (
                <RefreshCw className="w-3.5 h-3.5 animate-spin" />
              ) : (
                <Check className="w-3.5 h-3.5 mr-1" />
              )}
              Approuver
            </Button>
            <Button
              size="sm"
              variant="outline"
              onClick={() => rejectAction(action.id)}
              disabled={isProcessing}
              className="bg-rose-50 hover:bg-rose-100 border border-rose-200 text-rose-700 h-8 px-2.5 text-xs font-medium shadow-none"
            >
              <X className="w-3.5 h-3.5 mr-1" />
              Rejeter
            </Button>
          </>
        );
      
      case "approved":
      case "processing":
        return (
          <Button
            size="sm"
            variant="outline"
            onClick={() => stopAction(action.id)}
            disabled={isProcessing}
            className="bg-orange-50 hover:bg-orange-100 border border-orange-200 text-orange-700 h-8 px-2.5 text-xs font-medium shadow-none"
          >
            {isProcessing ? (
              <RefreshCw className="w-3.5 h-3.5 animate-spin" />
            ) : (
              <Square className="w-3.5 h-3.5 mr-1" />
            )}
            Stop
          </Button>
        );
      
      case "stopped":
        return (
          <Button
            size="sm"
            onClick={() => updateAction(action.id, "continue")}
            disabled={isProcessing}
            className="bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 text-emerald-700 h-8 px-2.5 text-xs font-medium shadow-none"
          >
            {isProcessing ? (
              <RefreshCw className="w-3.5 h-3.5 animate-spin" />
            ) : (
              <Play className="w-3.5 h-3.5 mr-1" />
            )}
            Continuer
          </Button>
        );

      case "rejected":
      case "failed":
        return (
          <Button
            size="sm"
            variant="outline"
            onClick={() => retryAction(action.id)}
            disabled={isProcessing}
            className="bg-violet-50 hover:bg-violet-100 border border-violet-200 text-violet-700 h-8 px-2.5 text-xs font-medium shadow-none"
          >
            {isProcessing ? (
              <RefreshCw className="w-3.5 h-3.5 animate-spin" />
            ) : (
              <RefreshCw className="w-3.5 h-3.5 mr-1" />
            )}
            R├®essayer
          </Button>
        );
      
      case "completed":
        // Aucun bouton pour les actions termin├®es
        return null;
      
      default:
        return null;
    }
  };

  const pendingCount = getCount("pending_approval");
  const approvedCount = getCount("approved");
  const completedCount = getCount("completed");
  const processingCount = getCount("processing") + getCount("stopped");
  const rejectedCount = getCount("rejected") + getCount("failed");

  return (
    <div className="space-y-6">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex items-center justify-between"
      >
        <div>
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            <Clock className="w-7 h-7 text-blue-600" />
            File d&apos;approbation
          </h1>
          <p className="text-gray-500 mt-1">
            Les actions LinkedIn cr├®├®es par l&apos;agent attendent votre
            approbation avant d&apos;├¬tre ex├®cut├®es.
          </p>
        </div>
        <Button
          variant="outline"
          onClick={() => fetchActionsAndStats()}
          disabled={isRefreshing}
          className="bg-white hover:bg-gray-50 border-gray-300 shadow-sm hover:shadow-md transition-all"
        >
          <RefreshCw
            className={`w-4 h-4 mr-2 ${
              isRefreshing ? "animate-spin text-blue-600" : "text-gray-600"
            }`}
          />
          {isRefreshing ? "Chargement..." : "Rafra├«chir"}
        </Button>
      </motion.div>

      {/* Stats cards */}
      <div className="grid grid-cols-1 md:grid-cols-6 gap-3">
        {/* En attente */}
        <Card
          className={`border-0 bg-gradient-to-br from-yellow-100 to-amber-100 dark:from-yellow-200/80 dark:to-amber-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === "pending_approval" ? "ring-2 ring-yellow-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus("pending_approval")}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#92400e' }}>
                En attente
              </p>
              <p className="text-xl font-bold" style={{ color: '#78350f' }}>
                {pendingCount}
              </p>
            </div>
            <Clock className="w-7 h-7" style={{ color: '#ca8a04' }} />
          </CardContent>
        </Card>

        {/* Approuv├®es = VERT */}
        <Card
          className={`border-0 bg-gradient-to-br from-green-100 to-emerald-100 dark:from-green-200/80 dark:to-emerald-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === "approved" ? "ring-2 ring-green-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus("approved")}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#166534' }}>
                Approuv├®es
              </p>
              <p className="text-xl font-bold" style={{ color: '#14532d' }}>
                {approvedCount}
              </p>
            </div>
            <Check className="w-7 h-7" style={{ color: '#16a34a' }} />
          </CardContent>
        </Card>

        {/* En cours = ORANGE */}
        <Card
          className={`border-0 bg-gradient-to-br from-orange-100 to-amber-100 dark:from-orange-200/80 dark:to-amber-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === "processing_stopped" ? "ring-2 ring-orange-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus("processing_stopped")}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#9a3412' }}>
                En cours
              </p>
              <p className="text-xl font-bold" style={{ color: '#7c2d12' }}>
                {processingCount}
              </p>
            </div>
            <Loader2 className="w-7 h-7" style={{ color: '#ea580c' }} />
          </CardContent>
        </Card>

        {/* Termin├®es = BLEU (coh├®rent avec campaigns) */}
        <Card
          className={`border-0 bg-gradient-to-br from-blue-100 to-sky-100 dark:from-blue-200/80 dark:to-sky-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === "completed" ? "ring-2 ring-blue-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus("completed")}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#1d4ed8' }}>
                Termin├®es
              </p>
              <p className="text-xl font-bold" style={{ color: '#1e40af' }}>
                {completedCount}
              </p>
            </div>
            <CheckCircle className="w-7 h-7" style={{ color: '#2563eb' }} />
          </CardContent>
        </Card>

        {/* Rejet├®es / ├®chou├®es = ROUGE */}
        <Card
          className={`border-0 bg-gradient-to-br from-red-100 to-rose-100 dark:from-red-200/80 dark:to-rose-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === "rejected_failed" ? "ring-2 ring-red-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus("rejected_failed")}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#991b1b' }}>
                Rejet├®es / ├®chou├®es
              </p>
              <p className="text-xl font-bold" style={{ color: '#7f1d1d' }}>
                {rejectedCount}
              </p>
            </div>
            <X className="w-7 h-7" style={{ color: '#dc2626' }} />
          </CardContent>
        </Card>

        {/* Total = VIOLET */}
        <Card
          className={`border-0 bg-gradient-to-br from-purple-100 to-violet-100 dark:from-purple-200/80 dark:to-violet-200/80 cursor-pointer transition-all duration-300 hover:shadow-md hover:scale-[1.02] rounded-xl ${
            selectedStatus === null ? "ring-2 ring-purple-500 ring-offset-2 shadow-md" : "shadow-sm"
          }`}
          onClick={() => filterByStatus(null)}
        >
          <CardContent className="p-3 flex items-center justify-between">
            <div>
              <p className="text-xs font-medium" style={{ color: '#7e22ce' }}>
                Total
              </p>
              <p className="text-xl font-bold" style={{ color: '#6b21a8' }}>
                {totalToday}
              </p>
            </div>
            <AlertCircle className="w-7 h-7" style={{ color: '#a855f7' }} />
          </CardContent>
        </Card>
      </div>

      {/* Liste des actions */}
      <Card className="border-0 shadow-sm bg-white/80 backdrop-blur-sm">
        <CardHeader className="py-3">
          <CardTitle className="text-base flex items-center gap-2">
            {selectedStatus === "pending_approval" && "Actions en attente d'approbation"}
            {selectedStatus === "approved" && "Actions approuv├®es"}
            {selectedStatus === "processing_stopped" && "Actions en cours"}
            {selectedStatus === "completed" && "Actions termin├®es"}
            {selectedStatus === "rejected_failed" && "Actions rejet├®es / ├®chou├®es"}
            {selectedStatus === null && "Toutes les actions"}
            {selectedStatus === "pending_approval" && pendingCount > 0 && (
              <Badge
                variant="secondary"
                className="bg-yellow-100 text-yellow-800"
              >
                {pendingCount}
              </Badge>
            )}
            {selectedStatus === "approved" && approvedCount > 0 && (
              <Badge
                variant="secondary"
                className="bg-blue-100 text-blue-800"
              >
                {approvedCount}
              </Badge>
            )}
            {selectedStatus === "processing_stopped" && processingCount > 0 && (
              <Badge
                variant="secondary"
                className="bg-orange-100 text-orange-800"
              >
                {processingCount}
              </Badge>
            )}
            {selectedStatus === "completed" && completedCount > 0 && (
              <Badge
                variant="secondary"
                className="bg-green-100 text-green-800"
              >
                {completedCount}
              </Badge>
            )}
            {selectedStatus === "rejected_failed" && rejectedCount > 0 && (
              <Badge
                variant="secondary"
                className="bg-red-100 text-red-800"
              >
                {rejectedCount}
              </Badge>
            )}
            {selectedStatus === null && actions.length > 0 && (
              <Badge
                variant="secondary"
                className="bg-purple-100 text-purple-800"
              >
                {actions.length}
              </Badge>
            )}
          </CardTitle>
        </CardHeader>
        <CardContent className="pb-4">
          {isLoading ? (
            <div className="text-center py-8 text-gray-500">
              <RefreshCw className="w-6 h-6 animate-spin mx-auto mb-2" />
              Chargement...
            </div>
          ) : actions.length === 0 ? (
            <div className="text-center py-10 text-gray-400">
              <Clock className="w-10 h-10 mx-auto mb-3 opacity-60" />
              <p className="text-base font-medium">
                {selectedStatus === null 
                  ? "Aucune action" 
                  : selectedStatus === "pending_approval"
                    ? "Aucune action en attente"
                    : selectedStatus === "approved"
                      ? "Aucune action approuv├®e"
                      : selectedStatus === "processing_stopped"
                        ? "Aucune action en cours"
                        : selectedStatus === "completed"
                          ? "Aucune action termin├®e"
                          : selectedStatus === "rejected_failed"
                            ? "Aucune action rejet├®e ou ├®chou├®e"
                            : "Aucune action dans cette cat├®gorie"}
              </p>
              <p className="text-xs mt-1">
                {selectedStatus === null 
                  ? "Les actions cr├®├®es par l'agent appara├«tront ici."
                  : "Cliquez sur une autre carte pour voir les actions."}
              </p>
            </div>
          ) : (
            <div className="space-y-3">
              {actions.map((action, index) => (
                <motion.div
                  key={action.id}
                  initial={{ opacity: 0, y: 12 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.04, duration: 0.3, ease: 'easeOut' }}
                  whileHover={{ scale: 1.005, y: -2 }}
                  className="border border-gray-200 rounded-xl p-4 bg-gradient-to-r from-white to-gray-100/60 hover:shadow-lg hover:border-purple-300 transition-all duration-300 cursor-default"
                >
                  <div className="flex items-start gap-4">
                    <div
                      className={`p-2.5 rounded-xl border-0 shadow-sm ${getActionBadgeColor(
                        action.status
                      )}`}
                    >
                      <div className={`w-5 h-5 ${getStatusIconColor(action.status)}`}>
                        {getActionIcon(action.action_type)}
                      </div>
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h4 className="font-semibold text-gray-900 text-sm">
                          {getActionLabel(action.action_type)}
                        </h4>
                        <Badge
                          variant="outline"
                          className="text-[10px] px-1.5 py-0.5 border-gray-200/60 text-gray-400 font-mono"
                        >
                          {action.id}
                        </Badge>
                        {getStatusBadge(action.status)}
                        {user?.role === "admin" && action.owner_name && (
                          <Badge
                            variant="secondary"
                            className="text-[10px] px-1.5 py-0 bg-blue-50 text-blue-600 border-blue-200"
                          >
                            {action.owner_name}
                          </Badge>
                        )}
                      </div>

                      {action.target_name && (
                        <p className="text-sm font-medium text-gray-700">
                          {action.target_name}
                        </p>
                      )}

                      {action.target_url && (
                        <a
                          href={action.target_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-xs text-blue-600 hover:underline flex items-center gap-1 mt-1"
                        >
                          {action.action_type === "search_and_message"
                            ? "Voir la liste des prospects"
                            : action.action_type === "search_and_connection"
                            ? "Voir la liste des connexions"
                            : `${action.target_url.substring(0, 60)}...`}
                          <ExternalLink className="w-3 h-3" />
                        </a>
                      )}

                      {action.action_type === "search_and_message" && (() => {
                        const p = typeof action.payload === "string" ? (() => { try { return JSON.parse(action.payload); } catch { return null; } })() : action.payload;
                        const msg = p?.message_template as string | undefined;
                        if (!msg) return null;
                        const isExpanded = expandedMessageId === action.id;
                        return (
                          <div className="mt-2">
                            <div className={`text-xs text-gray-700 bg-purple-50 border border-purple-100 rounded-lg p-3 leading-relaxed ${
                              isExpanded ? "" : "line-clamp-2"
                            }`}>
                              {msg}
                            </div>
                            <button
                              onClick={() => setExpandedMessageId(isExpanded ? null : action.id)}
                              className="mt-1 flex items-center gap-1 text-[11px] text-purple-600 hover:text-purple-800 font-medium"
                            >
                              {isExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                              {isExpanded ? "R├®duire" : "Voir le message complet"}
                            </button>
                          </div>
                        );
                      })()}

                      {action.action_type !== "search_and_message" && action.action_type !== "search_and_connection" && formatPayload(action) && (
                        <p className="text-xs text-gray-600 mt-2 bg-gray-50 p-2 rounded">
                          {formatPayload(action)}
                        </p>
                      )}


                      <p className="text-[11px] text-gray-300 mt-3 flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {new Date(
                          action.created_at
                        ).toLocaleString("fr-FR")}
                      </p>
                    </div>

                    <div className="flex flex-col gap-2">
                      {renderActionButtons(action)}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Info */}
      <Card className="bg-gradient-to-r from-blue-50 to-indigo-50/50 border-0 shadow-sm">
        <CardContent className="p-4">
          <div className="flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-blue-600 mt-0.5" />
            <div>
              <h4 className="font-medium text-blue-900">
                Comment ├ºa marche ?
              </h4>
              <p className="text-sm text-blue-800 mt-1 space-y-1">
                <span className="block">
                  1. L&apos;agent cr├®e une action (recherche, connexion, message) qui appara├«t ici en attente d&apos;approbation.
                </span>
                <span className="block">
                  2. Vous pouvez approuver ou rejeter chaque action, ainsi que la r├®essayer ou l&apos;arr├¬ter.
                </span>
                <span className="block">
                  3. Les actions approuv├®es sont ex├®cut├®es automatiquement par l&apos;extension Chrome, puis passent au statut ┬½ termin├®es ┬╗.
                </span>
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

