                          <span className="text-xs font-bold w-10 text-right">{rate(selected.connectionsAccepted, selected.connectionsSent)}</span>
                        </div>
                      </div>
                    </>) : (<>
                      {/* Stats pour campagne messages */}
                      <div className="flex gap-3 mb-3">
                        <div className="flex-1 bg-blue-50 rounded-lg py-3 px-2 text-center">
                          <p className="text-xl font-bold text-blue-600 leading-tight">{selected.contacted}</p>
                          <p className="text-xs text-gray-500">Contact├®s</p>
                        </div>
                        <div className="flex-1 bg-purple-50 rounded-lg py-3 px-2 text-center">
                          <p className="text-xl font-bold text-purple-600 leading-tight">{selected.replied}</p>
                          <p className="text-xs text-gray-500">R├®ponses</p>
                        </div>
                        <div className="flex-1 bg-green-50 rounded-lg py-3 px-2 text-center">
                          <p className="text-xl font-bold text-green-600 leading-tight">{selected.converted}</p>
                          <p className="text-xs text-gray-500">Conversions</p>
                        </div>
                      </div>
                      <div className="space-y-2">
                        {[
                          { label: "Taux de r├®ponse", value: rate(selected.replied, selected.contacted), color: "bg-purple-500" },
                          { label: "Conversion", value: rate(selected.converted, selected.contacted), color: "bg-green-500" },
                        ].map((m) => (
                          <div key={m.label} className="flex items-center gap-3">
                            <span className="text-xs text-gray-500 w-24 shrink-0">{m.label}</span>
                            <div className="flex-1 bg-gray-100 rounded-full h-2.5"><div className={`h-2.5 rounded-full ${m.color} transition-all duration-500`} style={{ width: m.value }} /></div>
                            <span className="text-xs font-bold w-10 text-right">{m.value}</span>
                          </div>
                        ))}
                      </div>
                    </>)}
                  </div>

                  {/* Actions */}
                  <div className="grid grid-cols-3 gap-2 pt-3 border-t border-gray-100">
                    <Button variant="outline" size="sm" className="text-xs" onClick={() => duplicateCampaign(selected)}><Copy className="w-3.5 h-3.5 mr-1" />Dupliquer</Button>
                    <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white text-xs" onClick={() => openEditModal(selected)}><Edit3 className="w-3.5 h-3.5 mr-1" />Modifier</Button>
                    <Button variant="outline" size="sm" className="text-xs text-red-500 border-red-200 hover:bg-red-50" onClick={() => deleteCampaign(selected.id, selected.name)}><Trash2 className="w-3.5 h-3.5 mr-1" />Supprimer</Button>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Modal de cr├®ation - 4 ├®tapes */}
      {mounted && showModal && typeof document !== "undefined" && createPortal(
        <div className="fixed inset-0 z-9999 flex items-center justify-center p-4">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-black/40" onClick={closeModal} />
          <motion.div initial={{ opacity: 0, scale: 0.9, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.9, y: 20 }} className="relative w-full max-w-3xl bg-white rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto">
            {/* Header avec bande color├®e subtile */}
            <div className="border-b border-gray-100 bg-white border-t-4 border-t-blue-500 px-6 pt-6 pb-5">
              <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-3">
                  <div className="w-11 h-11 bg-blue-50 rounded-xl flex items-center justify-center">
                    <Target className="w-5 h-5 text-blue-600" />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-gray-900">{editingCampaign ? 'Modifier la campagne' : 'Nouvelle campagne'}</h2>
                    <p className="text-sm text-gray-500">{editingCampaign ? 'Modifiez les param├¿tres de votre campagne' : 'Configurez votre prospection en 4 ├®tapes'}</p>
                  </div>
                </div>
                <button onClick={closeModal} className="w-9 h-9 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg flex items-center justify-center transition-colors"><X className="w-5 h-5" /></button>
              </div>
              {/* Stepper */}
              <div className="flex items-center justify-center gap-2">
                {[
                  { step: 0, label: "Type" },
                  { step: 1, label: "G├®n├®ral" },
                  { step: 2, label: "Ciblage" },
                  { step: 3, label: "Template" },
                  { step: 4, label: "Param├¿tres" },
                ].filter(s => {
                  if (s.step === 0) return true; // Toujours afficher l'├®tape Type
                  if (s.step === 3) return form.campaignType && form.campaignType !== 'connections_only'; // Template seulement si type d├®fini et pas connections_only
                  return true; // Autres ├®tapes toujours affich├®es
                }).map(({ step, label }) => {
                  const isStepCompleted = step === 0 ? form.campaignType !== '' : currentStep > step;
                  const isStepActive = currentStep === step;
                  return (
                    <div key={step} className="flex items-center">
                      <div className="flex flex-col items-center gap-1">
                        <motion.div className={`w-9 h-9 rounded-full flex items-center justify-center font-semibold text-sm transition-all ${isStepActive ? "bg-blue-600 text-white shadow-md shadow-blue-200" : isStepCompleted ? "bg-green-100 text-green-600" : "bg-gray-100 text-gray-400"}`}>
                          {isStepCompleted ? <CheckCircle className="w-4 h-4" /> : step}
                        </motion.div>
                        <span className={`text-[10px] font-medium ${isStepActive ? "text-blue-600" : isStepCompleted ? "text-green-600" : "text-gray-400"}`}>{label}</span>
                      </div>
                      {step < (form.campaignType && form.campaignType !== 'connections_only' ? 4 : 3) && <div className={`w-12 h-0.5 mx-1.5 mb-4 rounded-full transition-colors ${currentStep > step ? "bg-green-300" : "bg-gray-200"}`} />}
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Contenu des ├®tapes */}
            <div className="p-6">
              <AnimatePresence mode="wait">
                {currentStep === 0 && (
                  <motion.div key="step0" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
                    <div className="text-center mb-6">
                      <h3 className="text-xl font-bold text-gray-900">Type de campagne</h3>
                      <p className="text-gray-500">Choisissez comment vous souhaitez contacter vos prospects</p>
                    </div>
                    <div className="grid grid-cols-1 gap-4 max-w-md mx-auto">
                      {[
                        { icon: MessageSquare, label: "Messages", desc: "Envoyer des messages directs", value: "messages", color: "bg-blue-500" },
                        { icon: Users, label: "Connexions", desc: "Envoyer des demandes de connexion", value: "connections_only", color: "bg-purple-500" },
                        { icon: Send, label: "ConnexionsMessages", desc: "Connexions puis messages apr├¿s acceptation", value: "messages_and_connections", color: "bg-green-500" },
                      ].map((type) => (
                        <button key={type.label} onClick={() => setForm({ ...form, campaignType: type.value })} className={`p-4 border-2 rounded-xl text-left transition-all ${form.campaignType === type.value ? "border-blue-500 bg-blue-50 shadow-lg shadow-blue-500/20" : "border-gray-200 hover:border-gray-300 hover:shadow-md"}`}>
                          <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 ${type.color} rounded-xl flex items-center justify-center shrink-0`}><type.icon className="w-6 h-6 text-white" /></div>
                            <div className="flex-1 min-w-0">
                              <p className={`font-bold text-sm ${form.campaignType === type.value ? "text-blue-900" : "text-gray-900"}`}>{type.label}</p>
                              <p className="text-xs text-gray-500">{type.desc}</p>
                            </div>
                            {form.campaignType === type.value && <CheckCircle className="w-5 h-5 text-blue-600 shrink-0" />}
                          </div>
                        </button>
                      ))}
                    </div>
                  </motion.div>
                )}
                {currentStep === 1 && (
                  <motion.div key="step1" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
                    <div className="text-center mb-6">
                      <h3 className="text-xl font-bold text-gray-900">Informations g├®n├®rales</h3>
                      <p className="text-gray-500">Donnez un nom et une description ├á votre campagne</p>
                    </div>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Nom de la campagne <span className="text-red-500">*</span></label>
                        <div className="relative">
                          <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Ex: CEOs SaaS Paris" className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
                        </div>
                      </div>
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Description (optionnel)</label>
                        <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="D├®crivez l'objectif..." rows={3} className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none" />
                      </div>
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Objectif</label>
                        <div className="grid grid-cols-2 gap-3">
                          {[
                            { icon: Users, label: "G├®n├®rer des leads", desc: "Qualification" },
                            { icon: Mail, label: "D├®mos produit", desc: "Pr├®sentations" },
                            { icon: Globe, label: "├ëtendre le r├®seau", desc: "Connexions" },
                            { icon: TrendingUp, label: "Croissance", desc: "Acquisition" },
                          ].map((obj) => (
                            <button key={obj.label} onClick={() => setForm({ ...form, objective: obj.label })} className={`p-3 border-2 rounded-xl text-left transition-all ${form.objective === obj.label ? "border-blue-500 bg-blue-50" : "border-gray-200 hover:border-gray-300"}`}>
                              <div className="flex items-center gap-3">
                                <obj.icon className={`w-5 h-5 shrink-0 ${form.objective === obj.label ? "text-blue-600" : "text-gray-400"}`} />
                                <div className="flex-1 min-w-0">
                                  <p className={`font-semibold text-sm ${form.objective === obj.label ? "text-blue-900" : "text-gray-900"}`}>{obj.label}</p>
                                  <p className="text-xs text-gray-500">{obj.desc}</p>
                                </div>
                              </div>
                            </button>
                          ))}
                        </div>
                      </div>
                    </div>
                  </motion.div>
                )}

                {currentStep === 2 && (
                  <motion.div key="step2" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
                    <div className="text-center mb-6">
                      <h3 className="text-xl font-bold text-gray-900">Ciblage</h3>
                      <p className="text-gray-500">D├®finissez votre audience cible</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Profils cibles</label>
                        <div className="relative">
                          <Target className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                          <input value={form.target} onChange={(e) => setForm({ ...form, target: e.target.value })} placeholder="Ex: CEO, CTO, Founder" className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
                        </div>
                      </div>
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Industrie</label>
                        <Dropdown
                          ariaLabel="Industrie"
                          leftIcon={Building2}
                          value={form.industry}
                          onChange={(v) => setForm({ ...form, industry: v })}
                          options={industries.map((ind) => ({ value: ind, label: ind }))}
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Localisation</label>
                        <Dropdown
                          ariaLabel="Localisation"
                          leftIcon={MapPin}
                          value={form.location}
                          onChange={(v) => setForm({ ...form, location: v })}
                          options={locations.map((loc) => ({ value: loc, label: loc }))}
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Taille d&apos;entreprise</label>
                        <Dropdown
                          ariaLabel="Taille d'entreprise"
                          leftIcon={Users}
                          value={form.companySize}
                          onChange={(v) => setForm({ ...form, companySize: v })}
                          options={companySizes.map((size) => ({ value: size, label: size }))}
                        />
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-3">Niveau hi├®rarchique</label>
                      <div className="flex flex-wrap gap-2">
                        {seniorityOptions.map((seniority) => {
                          const isSelected = form.seniority.includes(seniority.id);
                          return (
                            <button key={seniority.id} onClick={() => { const newSeniority = isSelected ? form.seniority.filter((s) => s !== seniority.id) : [...form.seniority, seniority.id]; setForm({ ...form, seniority: newSeniority }); }} className={`flex items-center gap-2 px-4 py-2 rounded-xl border-2 transition-all ${isSelected ? "border-blue-500 bg-blue-50 text-blue-700" : "border-gray-200 hover:border-gray-300 text-gray-600"}`}>
                              <seniority.icon className={`w-4 h-4 ${isSelected ? "text-blue-600" : "text-gray-400"}`} />
                              <span className="text-sm font-medium">{seniority.label}</span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  </motion.div>
                )}

                {currentStep === 3 && (
                  <motion.div key="step3" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
                    <div className="text-center mb-6">
                      <h3 className="text-xl font-bold text-gray-900">Template de message</h3>
                      <p className="text-gray-500">Choisissez votre approche de prospection</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      {templates.map((template) => {
                        const isSelected = form.template === template.name;
                        return (
                          <motion.button key={template.name} whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => setForm({ ...form, template: template.name })} className={`p-4 border-2 rounded-2xl text-left transition-all ${isSelected ? "border-blue-500 bg-blue-50 shadow-lg shadow-blue-500/20" : "border-gray-200 hover:border-gray-300 hover:shadow-md"}`}>
                            <div className="flex items-center gap-3">
                              <div className={`w-10 h-10 ${template.color} rounded-xl flex items-center justify-center shrink-0`}><template.icon className="w-5 h-5 text-white" /></div>
                              <div className="flex-1 min-w-0">
                                <h4 className={`font-bold text-sm ${isSelected ? "text-blue-900" : "text-gray-900"}`}>{template.name}</h4>
                                <p className="text-xs text-gray-500">{template.desc}</p>
                              </div>
                              {isSelected && <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} className="w-5 h-5 bg-blue-500 rounded-full flex items-center justify-center shrink-0"><CheckCircle className="w-3 h-3 text-white" /></motion.div>}
                            </div>
                          </motion.button>
                        );
                      })}
                    </div>
                  </motion.div>
                )}

                {currentStep === 4 && (
                  <motion.div key="step4" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
                    <div className="text-center mb-6">
                      <h3 className="text-xl font-bold text-gray-900">Param├¿tres avanc├®s</h3>
                      <p className="text-gray-500">Configurez la cadence de votre campagne</p>
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                      <div className="bg-gray-50 rounded-2xl p-5">
                        <label className="block text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2"><Activity className="w-4 h-4 text-blue-500" />Limite quotidienne</label>
                        <div className="flex items-center justify-center">
                          <div className="relative">
                            <span className="w-24 text-center text-3xl font-bold text-gray-900 border-b-2 border-gray-300 py-2 inline-block">{form.dailyLimit}</span>
                            <span className="absolute right-0 bottom-3 text-sm text-gray-400">/jour</span>
                          </div>
                        </div>
                        <input type="range" min="5" max="20" value={form.dailyLimit} onChange={(e) => setForm({ ...form, dailyLimit: parseInt(e.target.value) })} className="w-full mt-4 accent-blue-600" />
                      </div>
                      <div className="bg-gray-50 rounded-2xl p-5">
                        <label className="block text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2"><Clock className="w-4 h-4 text-blue-500" />D├®lai de relance</label>
                        <div className="flex items-center justify-center">
                          <div className="relative">
                            <span className="w-24 text-center text-3xl font-bold text-gray-900 border-b-2 border-gray-300 py-2 inline-block">{form.followUpDays}</span>
                            <span className="absolute right-0 bottom-3 text-sm text-gray-400">jours</span>
                          </div>
                        </div>
                        <input type="range" min="1" max="14" value={form.followUpDays} onChange={(e) => setForm({ ...form, followUpDays: parseInt(e.target.value) })} className="w-full mt-4 accent-blue-600" />
                      </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Boutons de navigation */}
              <div className="flex justify-between pt-6 mt-6 border-t border-gray-100">
                <button onClick={prevStep} disabled={currentStep === 0} className={`flex items-center gap-2 px-6 py-3 rounded-xl font-semibold transition-colors ${currentStep === 0 ? "text-gray-300 cursor-not-allowed" : "text-gray-600 hover:bg-gray-100"}`}><ChevronLeft className="w-5 h-5" />Pr├®c├®dent</button>
                {currentStep < (form.campaignType === 'connections_only' ? 3 : 4) ? (
                  <button onClick={nextStep} disabled={currentStep === 0 && !form.campaignType || (currentStep === 1 && !form.name.trim())} className={`flex items-center gap-2 px-8 py-3 bg-blue-600 text-white rounded-xl font-semibold shadow-lg shadow-blue-500/30 transition-all ${((currentStep === 0 && !form.campaignType) || (currentStep === 1 && !form.name.trim())) ? "opacity-50 cursor-not-allowed" : "hover:bg-blue-700 hover:shadow-xl"}`}>Suivant<ChevronRight className="w-5 h-5" /></button>
                ) : (
                  <button onClick={createCampaign} className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl font-semibold shadow-lg shadow-purple-500/30 hover:shadow-xl transition-all">{editingCampaign ? 'Enregistrer' : 'Cr├®er la campagne'}</button>
                )}
              </div>
            </div>
          </motion.div>
        </div>,
        document.body
      )}

      {/* Delete Confirmation Modal */}
      {mounted && deleteConfirm && typeof document !== "undefined" && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/50"
            onClick={() => setDeleteConfirm(null)}
          />
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="relative w-full max-w-xs bg-white rounded-2xl shadow-xl overflow-hidden"
          >
            {/* Header */}
            <div className="bg-red-50 px-4 py-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-red-100 rounded-lg flex items-center justify-center shrink-0">
                  <Trash2 className="w-4 h-4 text-red-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-sm text-gray-900">Supprimer la campagne</h3>
                  <p className="text-xs text-gray-500">{deleteConfirm.campaignName}</p>
                </div>
              </div>
            </div>

            {/* Content */}
            <div className="p-4">
              <div className="text-center py-3">
                <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-2">
                  <Trash2 className="w-6 h-6 text-gray-400" />
                </div>
                <p className="text-sm font-medium text-gray-900">
                  Supprimer d├®finitivement cette campagne ?
                </p>
                <p className="text-xs text-gray-400 mt-1">Cette action est irr├®versible</p>
              </div>
            </div>

            {/* Footer */}
            <div className="px-4 py-3 border-t border-gray-100 bg-gray-50 flex gap-2">
              <button
                onClick={() => setDeleteConfirm(null)}
                disabled={deleting}
                className="flex-1 py-2 text-xs text-gray-600 hover:text-gray-900 font-medium transition-colors disabled:opacity-50"
              >
                Annuler
              </button>
              <button
                onClick={handleDeleteCampaign}
                disabled={deleting}
                className="flex-1 py-2 bg-red-600 text-white rounded-lg text-xs font-medium hover:bg-red-700 transition-colors disabled:opacity-50 flex items-center justify-center gap-1"
              >
                {deleting ? (
                  <>
                    <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Suppression...
                  </>
                ) : (
                  <>
                    <Trash2 className="w-3 h-3" />
                    Supprimer
                  </>
                )}
              </button>
            </div>
          </motion.div>
        </div>,
        document.body
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Settings, LayoutDashboard, Users, Target, Clock, Bot, Shield, LogOut } from "lucide-react";
import { useSettings } from "@/contexts/SettingsContext";
import { useAuth } from "@/contexts/AuthContext";
import NotificationPanel from "./NotificationPanel";

interface HeaderProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

export default function Header({ activeTab, setActiveTab }: HeaderProps) {
  const { t } = useSettings();
  const { user, isAdmin, logout } = useAuth();
  const [linkedInUser, setLinkedInUser] = useState<{ connected: boolean; name: string | null; email: string | null }>({ connected: false, name: null, email: null });

  useEffect(() => {
    async function fetchLinkedInAccount() {
      try {
        const res = await fetch('/api/linkedin-auth');
        const data = await res.json();
        setLinkedInUser({ connected: data.connected, name: data.name, email: data.email });
      } catch (e) {
        console.error('Error fetching LinkedIn account:', e);
      }
    }
    fetchLinkedInAccount();
  }, []);

  // Affichage nom/email selon le type d'utilisateur
  const displayName = user?.name || linkedInUser.name || 'Utilisateur';
  const displayEmail = user?.email || linkedInUser.email || '';
  const initials = displayName
    .split(' ')
    .map((w) => w[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);

  const goToSettings = () => {
    setActiveTab("settings");
    window.location.hash = "settings";
  };

  // Navigation adaptative selon le r├┤le
  const baseNav = [
    { id: "prospects", label: "Prospects", icon: Users },
    { id: "campaigns", label: t("Campagnes", "Campaigns"), icon: Target },
    { id: "approval", label: t("Approbations", "Approvals"), icon: Clock },
    { id: "agent", label: t("Agent IA", "AI Agent"), icon: Bot },
  ];

  const adminNav = [
    { id: "dashboard", label: t("Tableau de bord", "Dashboard"), icon: LayoutDashboard },
    ...baseNav,
    { id: "users", label: "Users", icon: Shield },
  ];

  const navItems = isAdmin ? adminNav : baseNav;

  return (
    <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-gray-100 shadow-sm">
      <div className="flex items-center justify-between px-4 lg:px-6 h-[75px]">
        {/* Logo */}
        <div className="flex items-center gap-2.5 shrink-0">
          <img
            src="/qlinqen-logo.png"
            alt="Qlinqen"
            className="h-10 w-auto object-contain"
          />
          
        </div>

        {/* Navigation ÔÇö Center */}
        <nav className="flex items-center gap-1 px-2 py-2 bg-gray-50/80 rounded-2xl border border-gray-100">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id);
                  window.location.hash = item.id;
                }}
                className={`
                  relative flex items-center gap-2 px-5 py-3 rounded-xl text-sm font-semibold transition-all duration-300 ease-out whitespace-nowrap
                  ${isActive
                    ? "bg-white text-blue-700 shadow-md shadow-blue-100/50"
                    : "text-gray-500 hover:text-gray-800 hover:bg-white/60"
                  }
                `}
              >
                <Icon className={`w-4 h-4 transition-colors duration-300 ${isActive ? "text-blue-600" : ""}`} />
                <span className="hidden lg:inline">{item.label}</span>
              </button>
            );
          })}
        </nav>

        {/* Right: Settings + Notifications + User */}
        <div className="flex items-center gap-2 shrink-0">
          {/* Notification & Settings icons ÔÇö same style */}
          <div className="flex items-center gap-1">
            <NotificationPanel />

            <button
              onClick={goToSettings}
              aria-label="Param├¿tres"
              className={`p-2 rounded-xl transition-all duration-200 ${
                activeTab === "settings"
                  ? "bg-blue-50 text-blue-600"
                  : "text-gray-400 hover:text-blue-600 hover:bg-blue-50/60"
              }`}
            >
              <Settings className="w-[18px] h-[18px]" />
            </button>
          </div>

          {/* Separator */}
          <div className="w-px h-15 bg-gray-200 mx-1 hidden sm:block" />

          {/* User */}
          <div className="flex items-center gap-2.5">
            <div className="hidden md:block text-right">
              <p className="text-sm font-semibold text-gray-800 leading-tight">{displayName}</p>
              <div className="flex items-center justify-end gap-1.5">
                {user?.role && (
                  <span className={`text-[10px] font-medium px-1.5 py-0.5 rounded-full ${
                    isAdmin
                      ? "bg-blue-50 text-blue-600 border border-blue-100"
                      : "bg-indigo-50 text-indigo-600 border border-indigo-100"
                  }`}>
                    {isAdmin ? "Admin" : "Membre"}
                  </span>
                )}
                {displayEmail && <span className="text-[11px] text-gray-400">{displayEmail}</span>}
              </div>
            </div>
            <button
              onClick={logout}
              title="D├®connexion"
              className="p-2 rounded-xl text-gray-400 hover:text-red-500 hover:bg-red-50 transition-all"
            >
              <LogOut className="w-[18px] h-[18px]" />
            </button>
          </div>
        </div>
      </div>
    </header>
  );
}

"use client";

import { useState, useEffect } from "react";
import { sendExtensionRequest } from "@/lib/extensionBridge";
import {
  CheckCircle,
  XCircle,
  Cookie,
  ExternalLink,
  LogOut,
  RefreshCw,
  Shield,
  AlertTriangle,
  Info,
  Eye,
  EyeOff,
  Copy,
  Check,
  Linkedin,
  User,
  Mail,
  Calendar,
  Wifi,
  WifiOff,
  ChevronRight,
  Puzzle,
} from "lucide-react";

interface LinkedInStatus {
  connected: boolean;
  email: string | null;
  name: string | null;
  auth_method: string | null;
  connected_at: string | null;
}

type AuthMethod = "cookie" | "extension" | null;

export default function LinkedInAccount() {
  const [status, setStatus] = useState<LinkedInStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedMethod, setSelectedMethod] = useState<AuthMethod>(null);

  // Cookie method state
  const [cookieValue, setCookieValue] = useState("");
  const [cookieName, setCookieName] = useState("");
  const [cookieEmail, setCookieEmail] = useState("");
  const [showCookie, setShowCookie] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [copied, setCopied] = useState(false);
  const [showDisconnectModal, setShowDisconnectModal] = useState(false);
  const [disconnecting, setDisconnecting] = useState(false);

  useEffect(() => {
    fetchStatus();
  }, []);

  async function fetchStatus() {
    setLoading(true);
    try {
      const res = await fetch("/api/linkedin-auth");
      const data = await res.json();
      setStatus(data);
    } catch {
      setStatus({ connected: false, email: null, name: null, auth_method: null, connected_at: null });
    } finally {
      setLoading(false);
    }
  }

  async function connectViaCookie() {
    if (!cookieValue.trim()) {
      setError("Le cookie est requis.");
      return;
    }
    setSaving(true);
    setError("");
    setSuccess("");
    try {
      const res = await fetch("/api/linkedin-auth", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          method: "cookie",
          cookie: cookieValue.trim(),
          email: cookieEmail.trim() || undefined,
          name: cookieName.trim() || undefined,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        setSuccess("Compte LinkedIn connect├® avec succ├®s via cookie !");
        setSelectedMethod(null);
        setCookieValue("");
        setCookieName("");
        setCookieEmail("");
        await fetchStatus();
      } else {
        setError(data.error || "Erreur lors de la connexion.");
      }
    } catch {
      setError("Erreur r├®seau. V├®rifiez que le serveur est lanc├®.");
    } finally {
      setSaving(false);
    }
  }

  async function fetchCookieViaExtension() {
    setError("");
    setSuccess("");
    setSaving(true);
    try {
      const result = await sendExtensionRequest("GET_LINKEDIN_COOKIE");
      if (result.success && typeof result.cookie === "string") {
        setCookieValue(result.cookie);
        setShowCookie(false);
      } else {
        const msg = result.error || "Impossible de r├®cup├®rer le cookie.";
        if (msg.includes("n'a pas r├®pondu")) {
          setError("Extension Chrome non d├®tect├®e. Installez/activez l'extension puis rechargez cette page.");
        } else {
          setError(msg);
        }
      }
    } finally {
      setSaving(false);
    }
  }

  async function connectViaExtension() {
    setSaving(true);
    setError("");
    setSuccess("");
    try {
      // Demander ├á l'extension de capturer le cookie li_at et de l'envoyer au backend
      const result = await sendExtensionRequest("CAPTURE_LINKEDIN_COOKIE");
      if (result.success) {
        setSuccess(result.message || "Compte LinkedIn connect├® via l'extension !");
        setSelectedMethod(null);
        await fetchStatus();
      } else {
        const msg = result.error || "Erreur lors de la capture par l'extension.";
        if (msg.toLowerCase().includes("li_at") || msg.toLowerCase().includes("cookie")) {
          setError("Cookie LinkedIn introuvable. Connectez-vous d'abord sur linkedin.com puis r├®essayez.");
        } else if (msg.includes("n'a pas r├®pondu")) {
          setError("Extension Chrome non d├®tect├®e. Installez/activez l'extension LinkedIn Agent puis rechargez cette page.");
        } else {
          setError(msg);
        }
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Erreur inconnue.");
    } finally {
      setSaving(false);
    }
  }

  async function confirmDisconnect() {
    setDisconnecting(true);
    try {
      await fetch("/api/linkedin-auth", { method: "DELETE" });
      setSelectedMethod(null);
      setStatus({ connected: false, email: null, name: null, auth_method: null, connected_at: null });
      setShowDisconnectModal(false);
    } catch {
      setError("Erreur lors de la d├®connexion.");
    } finally {
      setDisconnecting(false);
    }
  }

  function copyInstructions() {
    const text = "Comment trouver votre cookie LinkedIn :\n1. Ouvrez LinkedIn.com dans Chrome et connectez-vous\n2. Appuyez sur F12 pour ouvrir les DevTools\n3. Allez dans l'onglet Application > Cookies > linkedin.com\n4. Trouvez le cookie et copiez sa valeur";
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-40">
        <div className="flex flex-col items-center gap-3">
          <RefreshCw className="w-6 h-6 animate-spin text-blue-500" />
          <span className="text-sm text-gray-500">Chargement...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-5 animate-in fade-in duration-500">
      {/* ===== CONNECTION STATUS BANNER ===== */}
      <div className={`rounded-2xl p-5 border ${status?.connected
        ? "bg-white border-gray-200 shadow-sm"
        : "bg-white border-gray-200 shadow-sm"
      }`}>
        <div className="flex items-center justify-between">
          <div className="flex items-start gap-3">
            {/* Status Icon ÔÇö aligned with title */}
            <div className="flex items-center justify-center mt-0.5">
              {status?.connected
                ? <Linkedin className="w-5 h-5 text-blue-600" strokeWidth={1.5} />
                : <WifiOff className="w-5 h-5 text-gray-400" strokeWidth={1.5} />
              }
            </div>
            {/* Status Info */}
            <div>
              <div className="flex items-center gap-2">
                <span className="text-sm font-bold text-gray-900">
                  {status?.connected ? "Compte LinkedIn connect├®" : "Aucun compte connect├®"}
                </span>
                <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide ${status?.connected
                  ? "bg-blue-100 text-blue-700"
                  : "bg-gray-100 text-gray-500"
                }`}>
                  {status?.connected ? "Connect├®" : "D├®connect├®"}
                </span>
              </div>
              {status?.connected ? (
                <div className="flex items-center gap-4 mt-1.5 text-xs text-gray-600">
                  {status.name && (
                    <span className="flex items-center gap-1">
                      <User className="w-3.5 h-3.5 text-gray-400" />
                      {status.name}
                    </span>
                  )}
                  {status.email && (
                    <span className="flex items-center gap-1">
                      <Mail className="w-3.5 h-3.5 text-gray-400" />
                      {status.email}
                    </span>
                  )}
                  {status.auth_method && (
                    <span className="flex items-center gap-1">
                      {status.auth_method === "cookie"
                        ? <Cookie className="w-3.5 h-3.5 text-orange-500" />
                        : <Shield className="w-3.5 h-3.5 text-blue-500" />
                      }
                      {status.auth_method === "cookie" ? "Cookie" : "Extension"}
                    </span>
                  )}
                  {status.connected_at && (
                    <span className="flex items-center gap-1">
                      <Calendar className="w-3.5 h-3.5 text-gray-400" />
                      {new Date(status.connected_at).toLocaleDateString("fr-FR", { day: "numeric", month: "short", year: "numeric" })}
                    </span>
                  )}
                </div>
              ) : (
                <p className="text-xs text-gray-500 mt-1">Connectez votre compte pour activer les actions LinkedIn</p>
              )}
            </div>
          </div>
          {/* Actions */}
          <div className="flex items-center gap-2">
            <button
              onClick={fetchStatus}
              className="p-2 rounded-lg hover:bg-white/60 text-gray-400 hover:text-gray-600 transition-colors"
              title="Rafra\u00eechir le statut"
            >
              <RefreshCw className="w-4 h-4" />
            </button>
            {status?.connected && (
              <button
                onClick={() => setShowDisconnectModal(true)}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-white/80 hover:bg-red-50 border border-gray-200 hover:border-red-300 text-gray-600 hover:text-red-600 rounded-lg text-xs font-medium transition-all"
              >
                <LogOut className="w-3.5 h-3.5" />
                D├®connecter
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Feedback messages ÔÇö errors only */}
      {error && (
        <div className="flex items-start gap-2.5 p-3.5 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
          <AlertTriangle className="w-4 h-4 mt-0.5 shrink-0" />
          <span>{error}</span>
        </div>
      )}

      {/* ===== CONNECTION METHODS (shown when no form is selected) ===== */}
      {!selectedMethod && (
        <div>
          <h3 className="text-sm font-semibold text-gray-700 mb-3">
            {status?.connected ? "Changer de m├®thode" : "M├®thode de connexion"}
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {/* Cookie Method */}
            <button
              onClick={() => { setSelectedMethod("cookie"); setError(""); setSuccess(""); }}
              className="group relative flex items-center gap-4 p-4 bg-white border-2 border-gray-100 hover:border-orange-300 rounded-xl transition-all hover:shadow-md text-left"
            >
              <div className="w-11 h-11 bg-orange-100 group-hover:bg-orange-200 rounded-xl flex items-center justify-center transition-colors shrink-0">
                <Cookie className="w-5 h-5 text-orange-600" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="font-semibold text-gray-900 text-sm">Via Cookie</span>
                  <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 rounded text-[10px] font-bold uppercase">Recommanded</span>
                </div>
                <p className="text-xs text-gray-500 mt-0.5">Copiez le cookie depuis votre navigateur Chrome</p>
              </div>
              <ChevronRight className="w-4 h-4 text-gray-300 group-hover:text-orange-400 transition-colors shrink-0" />
            </button>

            {/* Extension Method */}
            <button
              onClick={() => { setSelectedMethod("extension"); setError(""); setSuccess(""); }}
              className="group relative flex items-center gap-4 p-4 bg-white border-2 border-gray-100 hover:border-blue-300 rounded-xl transition-all hover:shadow-md text-left"
            >
              <div className="w-11 h-11 bg-blue-100 group-hover:bg-blue-200 rounded-xl flex items-center justify-center transition-colors shrink-0">
                <Shield className="w-5 h-5 text-blue-600" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="font-semibold text-gray-900 text-sm">Via Extension</span>
                  <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 rounded text-[10px] font-bold uppercase">Automatique</span>
                </div>
                <p className="text-xs text-gray-500 mt-0.5">{"Capture automatique de session via l'extension Chrome"}</p>
              </div>
              <ChevronRight className="w-4 h-4 text-gray-300 group-hover:text-blue-400 transition-colors shrink-0" />
            </button>
          </div>

          {/* Extension info - inline */}
          <div className="mt-3 flex items-center gap-2 p-3 bg-slate-50 border border-slate-200 rounded-xl">
            <Info className="w-4 h-4 text-blue-500 shrink-0" />
            <p className="text-xs text-gray-600">
              {"L'extension LinkedIn Agent doit \u00eatre install├®e et active dans Chrome. Le statut \u00ab Connect├® \u00bb dans le popup de l'extension confirme que tout est op├®rationnel."}
            </p>
          </div>
        </div>
      )}

      {/* ===== COOKIE METHOD FORM ===== */}
      {selectedMethod === "cookie" && (
        <div className="border border-orange-200 bg-gradient-to-br from-orange-50 to-amber-50 rounded-xl p-5 space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Cookie className="w-5 h-5 text-orange-600" />
              <h3 className="font-bold text-gray-900 text-sm">Connexion par Cookie</h3>
            </div>
            <button onClick={() => setSelectedMethod(null)} className="text-xs text-gray-400 hover:text-gray-600 font-medium px-2 py-1 hover:bg-white/50 rounded-lg transition-colors">
              Annuler
            </button>
          </div>

          {/* Instructions */}
          <div className="bg-white rounded-lg border border-orange-100 p-3.5">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs font-semibold text-gray-700">Comment trouver votre cookie</span>
              <button onClick={copyInstructions} className="flex items-center gap-1 text-[11px] text-blue-600 hover:text-blue-800">
                {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
                {copied ? "Copi├® !" : "Copier"}
              </button>
            </div>
            <div className="flex flex-wrap gap-2">
              {[
                { n: "1", t: "Ouvrez linkedin.com" },
                { n: "2", t: "F12 \u2192 DevTools" },
                { n: "3", t: "Application \u2192 Cookies" },
                { n: "4", t: "Copiez" },
              ].map((step) => (
                <div key={step.n} className="flex items-center gap-1.5 px-2.5 py-1.5 bg-orange-50 rounded-lg">
                  <span className="w-4 h-4 bg-orange-200 text-orange-800 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0">{step.n}</span>
                  <span className="text-[11px] text-gray-700 font-medium">{step.t}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Form */}
          <div className="space-y-3">
            <div>
              <div className="flex items-center justify-between mb-1">
                <label className="block text-xs font-semibold text-gray-700">Cookie<span className="text-red-500">*</span></label>
                <button
                  type="button"
                  onClick={fetchCookieViaExtension}
                  disabled={saving}
                  className="flex items-center gap-1 text-[11px] text-blue-600 hover:text-blue-800 font-medium disabled:opacity-50"
                >
                  <Puzzle className="w-3 h-3" />
                  R├®cup├®rer via extension
                </button>
              </div>
              <div className="relative">
                <input
                  type={showCookie ? "text" : "password"}
                  value={cookieValue}
                  onChange={(e) => setCookieValue(e.target.value)}
                  placeholder="Collez votre cookie li_at ou cliquez sur R├®cup├®rer via extension"
                  className="w-full pr-10 pl-3 py-2.5 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-orange-400 focus:border-orange-400 bg-white"
                />
                <button
                  type="button"
                  onClick={() => setShowCookie(!showCookie)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                >
                  {showCookie ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs font-semibold text-gray-700 mb-1">Nom <span className="text-red-500">*</span></label>
                <input
                  type="text"
                  value={cookieName}
                  onChange={(e) => setCookieName(e.target.value)}
                  placeholder="Pr├®nom Nom"
                  className="w-full px-3 py-2.5 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-orange-400 focus:border-orange-400 bg-white"
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-700 mb-1">Email (optionnel)</label>
                <input
                  type="email"
                  value={cookieEmail}
                  onChange={(e) => setCookieEmail(e.target.value)}
                  placeholder="exemple@exemple.com"
                  className="w-full px-3 py-2.5 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-orange-400 focus:border-orange-400 bg-white"
                />
              </div>
            </div>
          </div>

          <button
