                )}
              </div>
            </motion.div>
          );
        })}
      </div>

      {/* Add Prospect Modal */}
      {mounted && showAddModal && typeof document !== "undefined" && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
