                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-gray-900">Nouveau prospect</h2>
                    <p className="text-sm text-gray-500">Ajouter ├á la colonne &quot;{pipelineData.find(s => s.id === addStage)?.status}&quot;</p>
