              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">T├®l├®phone</label>
                  <input
                    type="tel"
                    name="phone"
                    value={formData.phone}
