              </div>
            </div>

            {/* Error message */}
            {addError && (
              <div className="mx-5 mb-0 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2">
                <X className="w-4 h-4 text-red-500 shrink-0" />
