                <div className="text-center">
                  <p className="text-sm font-medium text-gray-900 mb-3 px-2 py-2 bg-gray-50 rounded-lg break-all">{contactPopup.value}</p>
                  <div className="flex gap-2">
                    <button
                      onClick={() => {
                        navigator.clipboard.writeText(contactPopup.value || '');
                        setContactPopup(null);
                      }}
                      className={`flex-1 py-2 rounded-lg text-xs font-medium text-white transition-colors ${
                        contactPopup.type === 'email' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-green-600 hover:bg-green-700'
                      }`}
                    >
                      Copier
                    </button>
                    {contactPopup.type === 'email' && (
                      <a 
                        href={`mailto:${contactPopup.value}`}
                        className="px-3 py-2 rounded-lg text-xs font-medium text-blue-600 bg-blue-50 hover:bg-blue-100 border border-blue-200"
                        title="Envoyer email"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                        </svg>
                      </a>
                    )}
                    {contactPopup.type === 'phone' && (
                      <a 
                        href={`tel:${contactPopup.value}`}
                        className="px-3 py-2 rounded-lg text-xs font-medium text-green-600 bg-green-50 hover:bg-green-100 border border-green-200"
                        title="Appeler"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" />
                        </svg>
                      </a>
                    )}
                  </div>
                </div>
              ) : (
                <div className="text-center py-3">
                  <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-2">
                    {contactPopup.type === 'email' ? <Mail className="w-6 h-6 text-gray-400" /> : <Phone className="w-6 h-6 text-gray-400" />}
                  </div>
                  <p className="text-gray-500 font-medium text-sm">
                    {contactPopup.type === 'email' ? 'Email indisponible' : 'Num├®ro indisponible'}
                  </p>
                  <p className="text-xs text-gray-400 mt-1">
                    Aucune information enregistr├®e
                  </p>
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="px-4 py-3 border-t border-gray-100 bg-gray-50">
              <button
                onClick={() => setContactPopup(null)}
                className="w-full py-2 text-xs text-gray-600 hover:text-gray-900 font-medium transition-colors"
              >
                Fermer
              </button>
            </div>
          </motion.div>
        </div>,
        document.body
      )}

      {/* Delete Confirmation Modal */}
      {mounted && deleteConfirm && typeof document !== "undefined" && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
            className="absolute inset-0 bg-black/50" 
            onClick={() => setDeleteConfirm(null)} 
          />
          <motion.div 
            initial={{ opacity: 0, scale: 0.9, y: 20 }} 
            animate={{ opacity: 1, scale: 1, y: 0 }} 
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="relative w-full max-w-xs bg-white rounded-2xl shadow-xl overflow-hidden"
          >
            {/* Header */}
            <div className="bg-red-50 px-4 py-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-red-100 rounded-lg flex items-center justify-center">
                  <Trash2 className="w-4 h-4 text-red-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-sm text-gray-900">Supprimer le prospect</h3>
                  <p className="text-xs text-gray-500">{deleteConfirm.prospectName}</p>
                </div>
              </div>
            </div>

            {/* Content */}
            <div className="p-4">
              <div className="text-center py-3">
                <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-2">
                  <Trash2 className="w-6 h-6 text-gray-400" />
                </div>
                <p className="text-gray-500 font-medium text-sm">
                  Supprimer d├®finitivement ce prospect ?
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Cette action est irr├®versible
                </p>
              </div>
            </div>

            {/* Footer */}
            <div className="px-4 py-3 border-t border-gray-100 bg-gray-50 flex gap-2">
              <button
                onClick={() => setDeleteConfirm(null)}
                disabled={deleting}
                className="flex-1 py-2 text-xs text-gray-600 hover:text-gray-900 font-medium transition-colors disabled:opacity-50"
              >
                Annuler
              </button>
              <button
                onClick={handleDeleteProspect}
                disabled={deleting}
                className="flex-1 py-2 bg-red-600 text-white rounded-lg text-xs font-medium hover:bg-red-700 transition-colors disabled:opacity-50 flex items-center justify-center gap-1"
              >
                {deleting ? (
                  <>
                    <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Suppression...
                  </>
                ) : (
                  <>
                    <Trash2 className="w-3 h-3" />
                    Supprimer
                  </>
                )}
              </button>
            </div>
          </motion.div>
        </div>,
        document.body
      )}
    </div>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { Badge } from "./ui/badge";
import { Button } from "./ui/button";
import { useState, useEffect } from "react";
import { 
  UserPlus, MessageSquare, MousePointerClick, CheckCircle, Clock, 
  Target, Filter, Activity, TrendingUp
} from "lucide-react";

interface Message {
  id: number;
  type: string;
  recipient_name: string;
  recipient_role: string;
  recipient_company: string;
  message_text: string;
  status: string;
  campaign_name: string;
  created_at: string;
}

const filters = ["Tous", "R├®ponses", "Conversions", "Connexions"];

const statusConfig: Record<string, { icon: React.ElementType; color: string; bgColor: string; badgeColor: string; badge: string; title: string }> = {
  replied: { icon: MessageSquare, color: "text-purple-600", bgColor: "bg-purple-50", badgeColor: "bg-purple-100 text-purple-700 border-purple-200", badge: "R├®ponse", title: "Message re├ºu" },
  converted: { icon: CheckCircle, color: "text-green-600", bgColor: "bg-green-50", badgeColor: "bg-green-100 text-green-700 border-green-200", badge: "Conversion", title: "Conversion" },
  sent: { icon: UserPlus, color: "text-blue-600", bgColor: "bg-blue-50", badgeColor: "bg-blue-100 text-blue-700 border-blue-200", badge: "Connexion", title: "Message envoy├®" },
  pending: { icon: Clock, color: "text-gray-600", bgColor: "bg-gray-50", badgeColor: "bg-gray-100 text-gray-700 border-gray-200", badge: "En attente", title: "En attente" },
};

function formatTimeAgo(dateString: string): string {
  const date = new Date(dateString);
  const now = new Date();
  const diffInHours = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60));
  
  if (diffInHours < 1) return "Il y a quelques minutes";
  if (diffInHours < 24) return `Il y a ${diffInHours}h`;
  return `Il y a ${Math.floor(diffInHours / 24)}j`;
}

export default function RecentActivity() {
  const [activeFilter, setActiveFilter] = useState("Tous");
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchMessages() {
      try {
        const response = await fetch('/api/messages?limit=12');
        const data = await response.json();
        if (data.success) {
          setMessages(data.messages);
        }
      } catch (error) {
        console.error('Error fetching messages:', error);
      } finally {
        setLoading(false);
      }
    }

    fetchMessages();
  }, []);

  const getMessageConfig = (status: string) => {
    return statusConfig[status] || statusConfig.pending;
  };

  const filteredMessages = activeFilter === "Tous" 
    ? messages 
    : messages.filter(m => {
        if (activeFilter === "R├®ponses") return m.status === 'replied';
        if (activeFilter === "Conversions") return m.status === 'converted';
        if (activeFilter === "Connexions") return m.status === 'sent';
        return true;
      });

  const stats = [
    { label: "Aujourd'hui", value: messages.length, icon: Clock },
    { label: "Conversions", value: messages.filter(m => m.status === 'converted').length, icon: CheckCircle },
    { label: "R├®ponses", value: messages.filter(m => m.status === 'replied').length, icon: MessageSquare },
  ];

  if (loading) {
    return (
      <Card className="border-0 shadow-lg overflow-hidden">
        <CardHeader className="border-b bg-gradient-to-r from-gray-50 to-white pb-4">
          <div className="h-8 bg-gray-200 rounded animate-pulse w-48" />
        </CardHeader>
        <CardContent className="p-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {[1, 2, 3, 4, 5, 6].map((i) => (
              <div key={i} className="h-32 bg-gray-100 rounded-xl animate-pulse" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="border-0 shadow-lg overflow-hidden">
      <CardHeader className="border-b border-gray-100 bg-gradient-to-r from-gray-50 to-white pb-4">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-gradient-to-br from-purple-100 to-blue-100 rounded-2xl flex items-center justify-center">
              <Activity className="w-6 h-6 text-purple-600" />
            </div>
            <div>
              <CardTitle className="text-xl">Activit├® R├®cente</CardTitle>
              <p className="text-sm text-gray-500">{filteredMessages.length} ├®v├®nements</p>
            </div>
          </div>
          
          {/* Quick Stats */}
          <div className="flex gap-3">
            {stats.map((stat) => (
              <div key={stat.label} className="flex items-center gap-2 px-3 py-2 bg-white rounded-xl border border-gray-200 shadow-sm">
                <stat.icon className="w-4 h-4 text-blue-500" />
                <div>
                  <p className="text-lg font-bold text-gray-900 leading-none">{stat.value}</p>
                  <p className="text-xs text-gray-500">{stat.label}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Filters */}
        <div className="flex items-center gap-2 mt-4 flex-wrap">
          {filters.map((f) => (
            <button
              key={f}
              onClick={() => setActiveFilter(f)}
              className={`px-4 py-2 text-sm font-medium rounded-full transition-all duration-300 ${
                activeFilter === f
                  ? "bg-blue-600 text-white shadow-md shadow-blue-600/20"
                  : "bg-gray-100 text-gray-600 hover:bg-gray-200"
              }`}
            >
              {f}
            </button>
          ))}
        </div>
      </CardHeader>

      <CardContent className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredMessages.length === 0 ? (
            <div className="col-span-full text-center py-12 text-gray-500">
              <Clock className="w-12 h-12 mx-auto mb-4 text-gray-300" />
              <p>Aucune activit├® r├®cente</p>
            </div>
          ) : (
            filteredMessages.map((message) => {
              const config = getMessageConfig(message.status);
              const Icon = config.icon;
              return (
                <div
                  key={message.id}
                  className="group flex gap-3 p-4 rounded-xl border border-gray-100 bg-white hover:shadow-lg hover:border-blue-200 hover:-translate-y-0.5 transition-all duration-300"
                >
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${config.bgColor} group-hover:scale-110 transition-transform duration-300`}>
                    <Icon className={`w-6 h-6 ${config.color}`} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between gap-2 mb-1">
                      <span className="text-sm font-bold text-gray-900">{config.title}</span>
                      <Badge className={`text-xs shrink-0 ${config.badgeColor}`}>{config.badge}</Badge>
                    </div>
                    <p className="text-sm font-semibold text-gray-800">{message.recipient_name}</p>
                    <p className="text-xs text-gray-500">{message.recipient_role} @ {message.recipient_company}</p>
                    <p className="text-xs text-gray-600 mt-2 leading-relaxed line-clamp-2 bg-gray-50 rounded-lg p-2">{message.message_text}</p>
                    <div className="flex items-center justify-between mt-3 pt-2 border-t border-gray-100">
                      <div className="flex items-center gap-1 text-xs text-gray-400">
                        <Target className="w-3 h-3" />
                        {message.campaign_name || 'Sans campagne'}
                      </div>
                      <div className="flex items-center gap-1 text-xs text-gray-400">
                        <Clock className="w-3 h-3" />
                        {formatTimeAgo(message.created_at)}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useSettings } from "@/contexts/SettingsContext";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "./ui/card";
import { Badge } from "./ui/badge";
