"use client";

import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/card";
import { Badge } from "../ui/badge";
import {
  Sankey, Tooltip as RTooltip, ResponsiveContainer, Layer, Rectangle,
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Cell,
} from "recharts";
import { Filter, ListChecks, Timer, GitBranch, Table, Download } from "lucide-react";
import { BIRange, downloadCSV } from "./biTypes";

interface FunnelStep {
  stage: string;
  key: string;
  value: number;
  color: string;
  conversionFromPrev: number;
  dropOff: number;
}
interface CycleStep { status: string; avgDays: number; count: number; }
interface CohortRow {
  week: string;
  total: number;
  identified: number;
  connected: number;
  contacted: number;
  responded: number;
  interested: number;
  converted: number;
}
interface SankeyData {
  nodes: { name: string }[];
  links: { source: number; target: number; value: number }[];
}

const NODE_COLORS = ["#94a3b8", "#60a5fa", "#3b82f6", "#8b5cf6", "#a855f7", "#10b981"];

function SankeyNode({ x, y, width, height, index, payload }: any) {
  const color = NODE_COLORS[index % NODE_COLORS.length];
  const isLeft = index < 0;
  const labelOffset = isLeft ? 12 : 8;
  return (
    <Layer>
      <Rectangle x={x} y={y} width={width} height={height} fill={color} fillOpacity={0.95} rx={2} />
      <text
        textAnchor={isLeft ? "start" : "end"}
        x={isLeft ? x + width + labelOffset : x - labelOffset}
        y={y + height / 2 + 3}
        fontSize="9"
        fontWeight="600"
        fill="currentColor"
        className="text-slate-700 dark:text-gray-100"
      >
        {payload.name}
      </text>
      <text
        textAnchor={isLeft ? "start" : "end"}
        x={isLeft ? x + width + labelOffset : x - labelOffset}
        y={y + height / 2 + 15}
        fontSize="8"
        fill="currentColor"
        className="text-slate-500 dark:text-gray-300"
      >
        {payload.value}
      </text>
    </Layer>
  );
}

export default function ConversionIntelligence({ range }: { range: BIRange }) {
  const [funnel, setFunnel] = useState<FunnelStep[]>([]);
  const [cycle, setCycle] = useState<CycleStep[]>([]);
  const [cohorts, setCohorts] = useState<CohortRow[]>([]);
  const [sankey, setSankey] = useState<SankeyData>({ nodes: [], links: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancel = false;
    setLoading(true);
    fetch(`/api/bi/conversion?range=${range}`)
      .then(r => r.json())
      .then(j => {
        if (cancel || !j.success) return;
        setFunnel(j.funnel || []);
        setCycle(j.cycleTime || []);
        setCohorts(j.cohorts || []);
        setSankey(j.sankey || { nodes: [], links: [] });
      })
      .finally(() => !cancel && setLoading(false));
    return () => { cancel = true; };
  }, [range]);

  const totalDropOff = funnel.reduce((s, f) => s + f.dropOff, 0);
  const overallConversion = funnel.length > 1 && funnel[0].value > 0
    ? Math.round((funnel[funnel.length - 1].value / funnel[0].value) * 1000) / 10
    : 0;

  const maxCohort = Math.max(1, ...cohorts.map(c => c.total));

  return (
    <Card className="border-0 shadow-lg overflow-hidden">
      <CardHeader className="bg-gradient-to-r from-blue-50 via-indigo-50 to-violet-50 border-b border-gray-100">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white rounded-xl shadow-sm flex items-center justify-center">
              <Filter className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <CardTitle className="text-lg">Conversion Intelligence</CardTitle>
              <p className="text-xs text-gray-500 mt-0.5">
                Parcours prospect ÔåÆ client ÔÇó drop-off, cycle time, cohortes
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Badge className="bg-blue-100 text-blue-700 border-0">
              {overallConversion}% conversion globale
            </Badge>
            <button
              onClick={() => downloadCSV(`funnel_${range}j.csv`, funnel)}
              className="p-2 rounded-lg hover:bg-white/60 text-gray-500 hover:text-gray-700 transition"
              title="Export CSV"
            >
              <Download className="w-4 h-4" />
            </button>
          </div>
        </div>
      </CardHeader>

      <CardContent className="p-6 space-y-6">
        {/* Sankey + Funnel side by side */}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
          {/* Sankey */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <h4 className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                <GitBranch className="w-4 h-4 text-blue-500" />
                Flux de conversion (Sankey)
              </h4>
            </div>
            <div className="bg-gradient-to-br from-gray-50 to-white rounded-xl border border-gray-100 p-3" style={{ height: 360 }}>
              {sankey.links.length > 0 && !loading ? (
                <ResponsiveContainer width="100%" height="100%">
                  <Sankey
                    data={sankey}
                    nodePadding={35}
                    nodeWidth={5}
                    linkCurvature={0.6}
                    iterations={64}
                    margin={{ top: 10, right: 40, bottom: 10, left: 70 }}
                    node={<SankeyNode />}
                    link={{ stroke: "#3b82f6", strokeOpacity: 0.18 }}
                  >
                    <RTooltip />
                  </Sankey>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-sm text-gray-400">
                  {loading ? "Chargement..." : "Pas assez de donn├®es pour la p├®riode s├®lectionn├®e"}
                </div>
              )}
            </div>
          </div>

          {/* Funnel d├®taill├® avec drop-off */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <h4 className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                <ListChecks className="w-4 h-4 text-indigo-500" />
                ├ëtapes du funnel & drop-off
              </h4>
              <span className="text-xs text-rose-600 font-semibold">
                Pertes totales: {totalDropOff}
              </span>
            </div>
            <div className="space-y-2">
              {funnel.map((step, i) => {
                const widthPct = funnel[0].value > 0
                  ? Math.max(8, (step.value / funnel[0].value) * 100)
                  : 0;
                return (
                  <motion.div
                    key={step.key}
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.06 }}
                    className="group"
                  >
                    <div className="flex items-center justify-between mb-1">
                      <div className="flex items-center gap-2">
                        <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: step.color }} />
                        <span className="text-sm font-semibold text-gray-700">{step.stage}</span>
                        {i > 0 && (
                          <Badge className={`text-[10px] border-0 ${
                            step.conversionFromPrev >= 50
                              ? "bg-emerald-50 text-emerald-700"
                              : step.conversionFromPrev >= 25
                              ? "bg-amber-50 text-amber-700"
                              : "bg-rose-50 text-rose-700"
                          }`}>
                            {step.conversionFromPrev}% vs ├®tape pr├®c├®dente
                          </Badge>
                        )}
                      </div>
                      <span className="text-sm font-bold text-gray-900 tabular-nums">{step.value}</span>
                    </div>
                    <div className="relative h-7 bg-gray-50 rounded-lg overflow-hidden">
                      <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${widthPct}%` }}
                        transition={{ duration: 0.6, delay: i * 0.06, ease: "easeOut" }}
                        className="h-full rounded-lg"
                        style={{
                          background: `linear-gradient(90deg, ${step.color}, ${step.color}cc)`,
                        }}
                      />
                      {i > 0 && step.dropOff > 0 && (
                        <div className="absolute right-1 top-1/2 -translate-y-1/2 text-[10px] font-bold text-rose-600 bg-rose-50 px-1.5 py-0.5 rounded">
                          ÔêÆ{step.dropOff} perdus
                        </div>
                      )}
                    </div>
                  </motion.div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Cycle time + Cohort heatmap */}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
          {/* Cycle time */}
          <div>
            <h4 className="text-sm font-semibold text-gray-700 mb-2 flex items-center gap-2">
              <Timer className="w-4 h-4 text-amber-500" />
              Cycle time moyen par ├®tape
            </h4>
            <div style={{ height: 240 }} className="bg-gradient-to-br from-gray-50 to-white rounded-xl border border-gray-100 p-3">
              {cycle.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={cycle} margin={{ top: 10, right: 20, left: 0, bottom: 0 }} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" horizontal={false} />
                    <XAxis type="number" axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 11 }} unit="j" />
                    <YAxis dataKey="status" type="category" width={90} axisLine={false} tickLine={false} tick={{ fill: "#475569", fontSize: 11, fontWeight: 500 }} />
                    <RTooltip
                      contentStyle={{ borderRadius: 12, border: "1px solid #e2e8f0" }}
                      formatter={(v: any) => [`${v} jours`, "Dur├®e moyenne"]}
                    />
                    <Bar dataKey="avgDays" radius={[0, 8, 8, 0]} barSize={20}>
                      {cycle.map((_, i) => (
                        <Cell key={i} fill={NODE_COLORS[i % NODE_COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-sm text-gray-400">
                  Aucune donn├®e de cycle disponible
                </div>
              )}
            </div>
          </div>

          {/* Cohort heatmap */}
          <div>
            <h4 className="text-sm font-semibold text-gray-700 mb-2 flex items-center gap-2">
              <Table className="w-4 h-4 text-violet-500" />
              Cohortes hebdomadaires
            </h4>
            <div className="bg-gradient-to-br from-gray-50 to-white rounded-xl border border-gray-100 p-3 overflow-x-auto" style={{ minHeight: 240 }}>
              {cohorts.length > 0 ? (
                <table className="w-full text-xs">
                  <thead>
                    <tr className="text-gray-500">
                      <th className="text-left p-1.5 font-semibold">Semaine</th>
                      <th className="p-1.5 font-semibold">Total</th>
                      <th className="p-1.5 font-semibold">Connect├®s</th>
                      <th className="p-1.5 font-semibold">Contact├®s</th>
                      <th className="p-1.5 font-semibold">R├®pondu</th>
                      <th className="p-1.5 font-semibold">Convertis</th>
                    </tr>
                  </thead>
                  <tbody>
                    {cohorts.map((c, i) => {
                      const cell = (val: number) => {
                        const intensity = Math.min(1, val / maxCohort);
                        const bg = `rgba(59, 130, 246, ${0.08 + intensity * 0.55})`;
                        return (
                          <td className="p-1 text-center">
                            <div
                              className="rounded-md py-1.5 font-semibold tabular-nums"
                              style={{ backgroundColor: bg, color: intensity > 0.5 ? "white" : "#1e3a8a" }}
                            >
                              {val}
                            </div>
                          </td>
                        );
                      };
                      return (
                        <tr key={i}>
                          <td className="p-1.5 text-gray-700 font-medium whitespace-nowrap">
                            {new Date(c.week).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}
                          </td>
                          {cell(c.total)}
                          {cell(c.connected)}
                          {cell(c.contacted)}
                          {cell(c.responded)}
                          {cell(c.converted)}
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              ) : (
                <div className="h-full flex items-center justify-center text-sm text-gray-400">
                  Pas de cohortes pour la p├®riode
                </div>
              )}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useState, useMemo } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/card";
import { Badge } from "../ui/badge";
import {
  ResponsiveContainer, Tooltip as RTooltip, AreaChart, Area, XAxis, YAxis,
  CartesianGrid, Legend, ReferenceLine,
} from "recharts";
import { TrendingUp, AlertTriangle, Telescope, SlidersHorizontal, CheckCircle2, Info } from "lucide-react";
import { BIRange } from "./biTypes";

interface HistPoint {
  day: string; x: number;
  newProspects: number; messages: number; replies: number; conversions: number;
}
interface ProjPoint extends Omit<HistPoint, "x"> {
  forecast: boolean;
}
interface Regression { slope: number; intercept: number; }
interface Alert { type: "positive" | "warning" | "info"; title: string; message: string; }

interface ForecastResp {
  history: HistPoint[];
  projection: ProjPoint[];
  regression: { prospects: Regression; messages: Regression; replies: Regression; conversions: Regression; };
  summary: { totalConversions: number; projectedConversions: number; avgDailyConversions: number; avgReplyRate: number; };
  alerts: Alert[];
}

const ALERT_STYLES: Record<Alert["type"], { bg: string; border: string; text: string; icon: any }> = {
  positive: { bg: "bg-emerald-50", border: "border-emerald-200", text: "text-emerald-800", icon: CheckCircle2 },
  warning: { bg: "bg-rose-50", border: "border-rose-200", text: "text-rose-800", icon: AlertTriangle },
  info: { bg: "bg-blue-50", border: "border-blue-200", text: "text-blue-800", icon: Info },
};

export default function Forecast({ range }: { range: BIRange }) {
  const [data, setData] = useState<ForecastResp | null>(null);
  const [loading, setLoading] = useState(true);
  const [whatIfBoost, setWhatIfBoost] = useState(0); // % boost messages quotidiens

  useEffect(() => {
    let cancel = false;
    queueMicrotask(() => setLoading(true));
    fetch(`/api/bi/forecast?range=${range}&horizon=30`)
      .then(r => r.json())
      .then(j => {
        if (cancel || !j.success) return;
        setData(j);
      })
      .finally(() => !cancel && setLoading(false));
    return () => { cancel = true; };
  }, [range]);

  // Combiner history + projection (avec what-if boost)
  const chartData = useMemo(() => {
    if (!data) return [];
    const factor = 1 + whatIfBoost / 100;
    const hist = data.history.map(h => ({
      day: h.day,
      historical: h.conversions,
      projected: null as number | null,
      boosted: null as number | null,
    }));
    const proj = data.projection.map(p => ({
      day: p.day,
      historical: null as number | null,
      projected: p.conversions,
      boosted: Math.round(p.conversions * factor),
    }));
    return [...hist, ...proj];
  }, [data, whatIfBoost]);

  const projectedTotal = data?.projection.reduce((s, p) => s + p.conversions, 0) || 0;
  const boostedTotal = Math.round(projectedTotal * (1 + whatIfBoost / 100));

  return (
    <Card className="border-0 shadow-lg overflow-hidden">
      <CardHeader className="bg-gradient-to-r from-cyan-50 via-sky-50 to-blue-50 border-b border-gray-100">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white rounded-xl shadow-sm flex items-center justify-center">
              <TrendingUp className="w-5 h-5 text-cyan-600" />
            </div>
            <div>
              <CardTitle className="text-lg">Predictive Forecast</CardTitle>
              <p className="text-xs text-gray-500 mt-0.5">
                Projection 30 jours ÔÇó alertes intelligentes ÔÇó simulateur what-if
              </p>
            </div>
          </div>
          {data && (
            <Badge className="bg-cyan-100 text-cyan-700 border-0">
              Projection: ~{projectedTotal} conversions / 30j
            </Badge>
          )}
        </div>
      </CardHeader>

      <CardContent className="p-6 space-y-6">
        {/* Alerts */}
        {data && data.alerts.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
            {data.alerts.map((a, i) => {
              const s = ALERT_STYLES[a.type];
              const Icon = s.icon;
              return (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.05 }}
                  className={`${s.bg} ${s.border} ${s.text} border rounded-xl p-3 flex items-start gap-2`}
                >
                  <Icon className="w-4 h-4 mt-0.5 shrink-0" />
                  <div className="text-xs">
                    <div className="font-semibold">{a.title}</div>
                    <div className="opacity-90 mt-0.5">{a.message}</div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        )}

        {/* Forecast chart */}
        <div>
          <h4 className="text-sm font-semibold text-gray-700 mb-2 flex items-center gap-2">
            <Telescope className="w-4 h-4 text-cyan-500" />
            Conversions: historique + projection 30 jours
          </h4>
          <div style={{ height: 320 }} className="bg-gradient-to-br from-gray-50 to-white rounded-xl border border-gray-100 p-3">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 10, right: 20, left: 0, bottom: 0 }}>
                  <defs>
                    <linearGradient id="histGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#10b981" stopOpacity={0.5} />
                      <stop offset="95%" stopColor="#10b981" stopOpacity={0.05} />
                    </linearGradient>
                    <linearGradient id="projGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#06b6d4" stopOpacity={0.4} />
                      <stop offset="95%" stopColor="#06b6d4" stopOpacity={0.05} />
                    </linearGradient>
                    <linearGradient id="boostGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#a855f7" stopOpacity={0.02} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                  <XAxis
                    dataKey="day"
                    axisLine={false}
                    tickLine={false}
                    tick={{ fill: "#64748b", fontSize: 10 }}
                    tickFormatter={(v) => new Date(v).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}
                  />
                  <YAxis axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 11 }} />
                  <RTooltip
                    contentStyle={{ borderRadius: 12, border: "1px solid #e2e8f0" }}
                    labelFormatter={(v) => new Date(v).toLocaleDateString("fr-FR")}
                  />
                  <Legend wrapperStyle={{ fontSize: 11 }} />
                  <ReferenceLine
                    x={data?.history[data.history.length - 1]?.day}
                    stroke="#94a3b8"
