                <div className="text-[11px] uppercase tracking-wide font-semibold text-gray-500">
                  {s.label}
                </div>
                <div className="text-xl font-bold text-gray-900 tabular-nums mt-1">
                  {s.value}{s.suffix}
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

