export function fmt(n: number | undefined | null): string {
  if (n === undefined || n === null || isNaN(n)) return "0";
  if (Math.abs(n) >= 1_000_000) return (n / 1_000_000).toFixed(1) + "M";
  if (Math.abs(n) >= 1_000) return (n / 1_000).toFixed(1) + "k";
  return Math.round(n).toString();
}

export function pctColor(delta: number): string {
  if (delta > 0) return "text-emerald-600 bg-emerald-50 border-emerald-100";
  if (delta < 0) return "text-rose-600 bg-rose-50 border-rose-100";
  return "text-gray-500 bg-gray-50 border-gray-100";
}

export function downloadCSV(filename: string, rows: Array<Record<string, any>>) {
  if (!rows.length) return;
  const headers = Object.keys(rows[0]);
  const csv = [
    headers.join(","),
    ...rows.map(r =>
      headers
        .map(h => {
          const v = r[h];
          if (v === null || v === undefined) return "";
          const s = String(v).replace(/"/g, '""');
          return /[,"\n]/.test(s) ? `"${s}"` : s;
        })
        .join(",")
    ),
  ].join("\n");
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

"use client";

import React, { createContext, useContext, useState, useEffect, useCallback } from "react";

// Patch global de fetch : injecte automatiquement le token JWT (utilisateurs secondaires)
// sur tous les appels vers /api. Les admins (session LinkedIn par cookie) n'ont pas de token
// et sont r├®solus c├┤t├® serveur. S'ex├®cute une seule fois c├┤t├® client.
if (typeof window !== "undefined" && !(window as any).__authFetchPatched) {
  (window as any).__authFetchPatched = true;
  const originalFetch = window.fetch.bind(window);
  window.fetch = (input: RequestInfo | URL, init?: RequestInit) => {
    try {
      const url =
        typeof input === "string"
          ? input
          : input instanceof URL
          ? input.toString()
          : (input as Request).url;
      const isApi =
        !!url &&
        (url.startsWith("/api/") || url.startsWith(`${window.location.origin}/api/`));
      const token = localStorage.getItem("auth_token");
      if (isApi && token) {
        const headers = new Headers(
          init?.headers || (input instanceof Request ? input.headers : undefined)
        );
        if (!headers.has("Authorization")) {
          headers.set("Authorization", `Bearer ${token}`);
        }
        init = { ...init, headers };
      }
    } catch {
      // En cas d'erreur, on laisse passer la requ├¬te originale sans modification
    }
    return originalFetch(input as any, init);
  };
}

export interface AuthUser {
  id: number;
  name: string;
  email: string;
  role: "admin" | "user";
  adminId?: number | null;
  linkedinConnected?: boolean;
}

interface AuthContextType {
  user: AuthUser | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  isAdmin: boolean;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [loading, setLoading] = useState(true);

  const resolveUser = useCallback(async () => {
    try {
      const token = localStorage.getItem("auth_token");
      const headers: Record<string, string> = {};
      if (token) headers["Authorization"] = `Bearer ${token}`;

      const res = await fetch("/api/auth/me", { headers });
      const data = await res.json();

      if (data.success && data.user) {
        setUser({
          id: data.user.id,
          name: data.user.name,
          email: data.user.email,
          role: data.user.role === "admin" ? "admin" : "user",
          adminId: data.user.adminId || data.user.admin_id || null,
          linkedinConnected: data.user.linkedinConnected || data.user.linkedin_connected,
        });
      } else {
        setUser(null);
      }
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    resolveUser();
  }, [resolveUser]);

  const login = async (email: string, password: string) => {
    try {
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();

      if (data.success && data.token) {
        localStorage.setItem("auth_token", data.token);
        setUser({
          id: data.user.id,
          name: data.user.name,
          email: data.user.email,
          role: data.user.role,
          adminId: data.user.adminId,
        });
        return { success: true };
      }
      return { success: false, error: data.error || "Erreur de connexion" };
    } catch {
      return { success: false, error: "Erreur r├®seau" };
    }
  };

  const logout = async () => {
    // Supprimer le token JWT (user secondaire)
    localStorage.removeItem("auth_token");
    // Supprimer la session LinkedIn (admin)
    try {
      await fetch("/api/linkedin-auth", { method: "DELETE" });
    } catch {
      // ignore
    }
    setUser(null);
    window.location.href = "/login";
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        loading,
        login,
        logout,
        isAdmin: user?.role === "admin",
        refreshUser: resolveUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be inside AuthProvider");
  return ctx;
}

import { ChatOpenAI } from "@langchain/openai";
import { AIMessage, HumanMessage, SystemMessage, BaseMessage } from "@langchain/core/messages";
import { OPENAI_CONFIG, SYSTEM_PROMPTS } from "./agent-config";
import { ALL_TOOLS, TOOLS_MAP } from "./tools";

// Type pour les messages
export interface AgentMessage {
  role: "user" | "assistant" | "system";
  content: string;
  timestamp?: Date;
}

export interface ToolStep {
  toolName: string;
  args: Record<string, unknown>;
  result: string;
  status: "success" | "error";
  timestamp: string;
}

export interface AgentChatResult {
  response: string;
  toolSteps: ToolStep[];
}

// Cr├®er le mod├¿le LLM avec OpenAI + tool binding
function createBoundLLM(modelName?: string) {
  const llm = new ChatOpenAI({
    modelName: modelName || OPENAI_CONFIG.model,
    temperature: OPENAI_CONFIG.temperature,
    maxTokens: OPENAI_CONFIG.maxTokens,
    openAIApiKey: process.env.OPENAI_API_KEY,
  });

  return llm.bindTools(ALL_TOOLS);
}

// Classe principale pour g├®rer l'agent
export class LinkedInAgent {
  private history: BaseMessage[] = [];
  private maxHistory = 20;

  // Envoyer un message ├á l'agent ÔÇö boucle multi-tool pour cha├«ner les actions
  async chat(userMessage: string, context?: Record<string, unknown>, modelName?: string): Promise<AgentChatResult> {
    const toolSteps: ToolStep[] = [];
    const MAX_TOOL_ROUNDS = 6; // Max 6 rounds de tool calls pour ├®viter les boucles infinies

    try {
      const llm = createBoundLLM(modelName);

      // Extraire les settings du contexte (ton, langue)
      const tone = context?.tone as string | undefined;
      const autoDetectLang = context?.autoDetectLanguage !== false;
      const toneInstruction = tone ? `\n\nÔä╣´©Å TON IMPOSE: Utilise un ton ${tone} dans TOUS tes messages. Adapte le style de r├®daction en cons├®quence.` : '';
      const langInstruction = autoDetectLang ? '\n\u2139´©Å LANGUE: D├®tecte la langue du prospect et r├®ponds-lui dans SA LANGUE si elle est diff├®rente du fran├ºais.' : '';

      // Construire le prompt avec contexte
      let input = userMessage;
      if (context) {
        // Exclude internal settings keys from context shown to LLM
        const { tone: _t, autoDetectLanguage: _l, ...displayCtx } = context;
        if (Object.keys(displayCtx).length > 0) {
          input = `[Contexte: ${JSON.stringify(displayCtx)}]\n\n${userMessage}`;
        }
      }

      // Messages pour le LLM
      const messages: BaseMessage[] = [
        new SystemMessage(`${SYSTEM_PROMPTS.prospecting}${toneInstruction}${langInstruction}

RAPPEL CRITIQUE:
- TOUTES les actions passent par la file d'approbation. AUCUNE action ne s'ex├®cute directement.
- Quand on te demande d'envoyer un message ├á UN prospect connu ÔåÆ appelle linkedin_send_message DIRECTEMENT.
- Quand on te demande d'envoyer une connexion ÔåÆ appelle linkedin_send_connection DIRECTEMENT.
- Quand on te demande de chercher dans le r├®seau et contacter des gens ÔåÆ WORKFLOW B:
  Appelle linkedin_search(network='F', message_template='...') avec un message personnalis├®.
  Le message_template peut contenir {name} qui sera remplac├® automatiquement.
  L'extension fait tout: recherche ÔåÆ profils ÔåÆ envoie les messages.
- MULTI-CAT├ëGORIES: Si l'utilisateur mentionne PLUSIEURS groupes/cat├®gories (ex: "├®tudiants ESIEA et employ├®s Phinia"), tu DOIS faire UN appel linkedin_search S├ëPAR├ë pour CHAQUE cat├®gorie. LinkedIn cherche en AND pas en OR. Appelle linkedin_search plusieurs fois dans la m├¬me r├®ponse.
- IMPORTANT: Quand l'utilisateur veut chercher ET envoyer un message, TOUJOURS inclure message_template dans linkedin_search. R├®dige toi-m├¬me le message personnalis├®.
- IMPORTANT: Apr├¿s linkedin_search, NE PAS appeler get_search_results ou bulk_send_messages. Tout est automatique.
- Ne JAMAIS afficher un message ├á copier-coller. TOUJOURS utiliser le tool pour cr├®er l'action.
- Si l'utilisateur ne fournit PAS de nom/URL ÔåÆ utiliser linkedin_search pour trouver les prospects, PAS demander le nom/URL.
- R├®ponds toujours en fran├ºais, de mani├¿re claire et structur├®e.`),
        ...this.history,
        new HumanMessage(input),
      ];

      // Boucle multi-tool: le LLM peut appeler des tools, recevoir les r├®sultats,
      // puis d├®cider d'appeler d'autres tools ÔÇö jusqu'├á ce qu'il donne une r├®ponse finale
      const currentMessages = [...messages];
      let finalOutput = "";

      for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
        const response = await llm.invoke(currentMessages);

        // Si pas de tool calls ÔåÆ c'est la r├®ponse finale
        if (!response.tool_calls || response.tool_calls.length === 0) {
          finalOutput = response.content?.toString() || "Action ex├®cut├®e avec succ├¿s.";
          break;
        }

        // Ex├®cuter les tool calls (TOUS les appels parall├¿les d'un m├¬me batch)
        let toolResults = "";
        let actionsCreatedCount = 0;
        // Tools qui stoppent la boucle apr├¿s ex├®cution: recherche (attend approbation) + envoi
        const STOP_LOOP_TOOLS = ["linkedin_search", "linkedin_send_message", "linkedin_send_connection", "bulk_send_messages"];

        for (const toolCall of response.tool_calls) {
          const tool = TOOLS_MAP[toolCall.name];
          if (tool) {
            try {
              const result = await tool.invoke(toolCall.args);
              const resultStr = typeof result === "string" ? result : JSON.stringify(result);
              toolResults += `\n[R├®sultat de ${toolCall.name}]: ${resultStr}`;
              toolSteps.push({
                toolName: toolCall.name,
                args: toolCall.args as Record<string, unknown>,
                result: resultStr,
                status: "success",
                timestamp: new Date().toISOString(),
              });
              // Compter les actions LinkedIn cr├®├®es
              if (STOP_LOOP_TOOLS.includes(toolCall.name) && resultStr.includes('"success":true')) {
                actionsCreatedCount++;
              }
            } catch (toolError) {
              const errMsg = toolError instanceof Error ? toolError.message : "Erreur";
              toolResults += `\n[Erreur ${toolCall.name}]: ${errMsg}`;
              toolSteps.push({
                toolName: toolCall.name,
                args: toolCall.args as Record<string, unknown>,
                result: errMsg,
                status: "error",
                timestamp: new Date().toISOString(),
              });
            }
          }
        }

        // Si des actions LinkedIn ont ├®t├® cr├®├®es ÔåÆ STOP, pas besoin de continuer la boucle
        if (actionsCreatedCount > 0) {
          const plural = actionsCreatedCount > 1 ? `${actionsCreatedCount} actions ont ├®t├® cr├®├®es` : "L'action a ├®t├® cr├®├®e";
          currentMessages.push(new AIMessage(response.content?.toString() || ""));
          currentMessages.push(new HumanMessage(
            `R├®sultats des tools ex├®cut├®s:${toolResults}\n\n${plural} avec succ├¿s. NE RAPPELLE PAS le m├¬me tool. Donne ta r├®ponse finale ├á l'utilisateur pour confirmer les ${actionsCreatedCount} action(s) cr├®├®e(s).`
          ));
          // Un dernier round pour la r├®ponse finale uniquement
          const finalResponse = await llm.invoke(currentMessages);
          finalOutput = finalResponse.content?.toString() || "Action cr├®├®e avec succ├¿s.";
          break;
        }

        // Ajouter la r├®ponse de l'assistant + r├®sultats des tools aux messages
        currentMessages.push(new AIMessage(response.content?.toString() || ""));
        currentMessages.push(new HumanMessage(
          `R├®sultats des tools ex├®cut├®s:${toolResults}\n\nContinue le workflow si n├®cessaire. NE RAPPELLE PAS un tool d├®j├á appel├® avec les m├¬mes arguments. Sinon, donne ta r├®ponse finale.`
        ));
      }

      // Si on a atteint MAX_TOOL_ROUNDS sans r├®ponse finale
      if (!finalOutput) {
        finalOutput = "Les actions ont ├®t├® ex├®cut├®es. Consultez l'onglet Approbations pour les d├®tails.";
      }

      this.addToHistory(userMessage, finalOutput);
      return { response: finalOutput, toolSteps };

    } catch (error) {
      console.error("Agent error:", error);
      const errorMsg = error instanceof Error ? error.message : "Erreur inconnue";

      if (errorMsg.includes("API key") || errorMsg.includes("401") || errorMsg.includes("Unauthorized")) {
        return { response: "Erreur: Cl├® API OpenAI invalide ou manquante. V├®rifiez OPENAI_API_KEY dans .env.local.", toolSteps };
      }
      if (errorMsg.includes("model") || errorMsg.includes("404")) {
        return { response: "Erreur: Mod├¿le non trouv├®. V├®rifiez OPENAI_MODEL dans .env.local.", toolSteps };
      }

      return { response: `D├®sol├®, j'ai rencontr├® une erreur: ${errorMsg}. Veuillez r├®essayer.`, toolSteps };
    }
  }

  // Ajouter ├á l'historique (avec limite)
  private addToHistory(userMessage: string, assistantResponse: string) {
    this.history.push(new HumanMessage(userMessage));
    this.history.push(new AIMessage(assistantResponse));

    if (this.history.length > this.maxHistory * 2) {
      this.history = this.history.slice(-this.maxHistory * 2);
    }
  }

  // Effacer l'historique
  clearHistory() {
    this.history = [];
  }

  // Restaurer l'historique depuis des messages DB (pour reprendre une conversation)
  restoreHistory(messages: { role: string; content: string }[]) {
    this.history = [];
    for (const msg of messages) {
      if (msg.role === "user") {
        this.history.push(new HumanMessage(msg.content));
      } else if (msg.role === "assistant") {
        this.history.push(new AIMessage(msg.content));
      }
    }
    // Limiter
    if (this.history.length > this.maxHistory * 2) {
      this.history = this.history.slice(-this.maxHistory * 2);
    }
  }

  // Obtenir l'historique
  getHistory(): AgentMessage[] {
    return this.history.map((msg) => ({
      role: msg instanceof HumanMessage ? ("user" as const) : ("assistant" as const),
      content: msg.content.toString(),
      timestamp: new Date(),
    }));
  }
}

