// =============================================
// Structured Logger with Persistent Storage
// Remplace console.log par un syst├¿me formalis├®
// =============================================

import { pool } from "./db";

export type LogLevel = "debug" | "info" | "warn" | "error" | "fatal";

interface LogEntry {
  level: LogLevel;
  message: string;
  context?: Record<string, any>;
  timestamp: string;
  source?: string;
}

class Logger {
  private buffer: LogEntry[] = [];
  private readonly BUFFER_LIMIT = 1000;
  private readonly LEVELS: Record<LogLevel, number> = {
    debug: 0,
    info: 1,
    warn: 2,
    error: 3,
    fatal: 4,
  };
  private minLevel: LogLevel =
    (process.env.LOG_LEVEL as LogLevel) || "info";

  private shouldLog(level: LogLevel): boolean {
    return this.LEVELS[level] >= this.LEVELS[this.minLevel];
  }

  private log(level: LogLevel, message: string, context?: Record<string, any>): void {
    if (!this.shouldLog(level)) return;

    const entry: LogEntry = {
      level,
      message,
      context,
      timestamp: new Date().toISOString(),
      source: context?.source,
    };

    this.buffer.push(entry);
    if (this.buffer.length > this.BUFFER_LIMIT) {
      this.buffer = this.buffer.slice(-this.BUFFER_LIMIT);
    }

    // Output to console with colors
    const icon = { debug: "­ƒöì", info: "Ôä╣´©Å", warn: "ÔÜá´©Å", error: "ÔØî", fatal: "­ƒöÑ" }[level];
    const log = level === "error" || level === "fatal" ? console.error :
                level === "warn" ? console.warn : console.log;
    log(`${icon} [${level.toUpperCase()}] ${message}`, context || "");

    // Persist errors to database (async, non-blocking)
    if (level === "error" || level === "fatal") {
      this.persistError(entry).catch(() => {});
    }
  }

  private async persistError(entry: LogEntry): Promise<void> {
    try {
      await pool.query(
        `INSERT INTO error_logs (level, message, context, source, created_at)
         VALUES ($1, $2, $3, $4, NOW())
         ON CONFLICT DO NOTHING`,
        [entry.level, entry.message, JSON.stringify(entry.context || {}), entry.source || null]
      );
    } catch {
      // Si la table n'existe pas, ignore silencieusement
    }
  }

  debug(message: string, context?: Record<string, any>): void {
    this.log("debug", message, context);
  }
  info(message: string, context?: Record<string, any>): void {
    this.log("info", message, context);
  }
  warn(message: string, context?: Record<string, any>): void {
    this.log("warn", message, context);
  }
  error(message: string, context?: Record<string, any>): void {
    this.log("error", message, context);
  }
  fatal(message: string, context?: Record<string, any>): void {
    this.log("fatal", message, context);
  }

  getRecent(limit = 100, level?: LogLevel): LogEntry[] {
    let logs = this.buffer;
    if (level) {
      logs = logs.filter((l) => this.LEVELS[l.level] >= this.LEVELS[level]);
    }
    return logs.slice(-limit);
  }

  getStats() {
    const counts: Record<LogLevel, number> = {
      debug: 0, info: 0, warn: 0, error: 0, fatal: 0,
    };
    for (const log of this.buffer) counts[log.level]++;
    return { total: this.buffer.length, byLevel: counts };
  }
}

export const logger = new Logger();

// =============================================
// Performance Monitoring
// Mesure les temps de r├®ponse des APIs et requ├¬tes DB
// =============================================

interface PerfMetric {
  name: string;
  duration: number;
  timestamp: number;
  metadata?: Record<string, any>;
}

class PerformanceMonitor {
  private metrics: PerfMetric[] = [];
  private readonly MAX_METRICS = 1000;
  private readonly SLOW_THRESHOLD_MS = 500;

  record(name: string, duration: number, metadata?: Record<string, any>): void {
    this.metrics.push({
      name,
      duration,
      timestamp: Date.now(),
      metadata,
    });

    // Keep only last N metrics to avoid memory leaks
    if (this.metrics.length > this.MAX_METRICS) {
      this.metrics = this.metrics.slice(-this.MAX_METRICS);
    }

    // Log slow operations
    if (duration > this.SLOW_THRESHOLD_MS) {
      console.warn(
        `[PERF] ÔÜá´©Å Slow operation: ${name} took ${duration}ms`,
        metadata || ""
      );
    }
  }

  // Wrapper pour mesurer une fonction async
  async measure<T>(
    name: string,
    fn: () => Promise<T>,
    metadata?: Record<string, any>
  ): Promise<T> {
    const start = performance.now();
    try {
      const result = await fn();
      const duration = performance.now() - start;
      this.record(name, duration, metadata);
      return result;
    } catch (error) {
      const duration = performance.now() - start;
      this.record(name, duration, { ...metadata, error: true });
      throw error;
    }
  }

  // Statistiques agr├®g├®es
  getStats(name?: string) {
    const filtered = name
      ? this.metrics.filter((m) => m.name === name)
      : this.metrics;

    if (filtered.length === 0) {
      return { count: 0, avg: 0, min: 0, max: 0, p95: 0 };
    }

    const durations = filtered.map((m) => m.duration).sort((a, b) => a - b);
    const sum = durations.reduce((a, b) => a + b, 0);
    const p95Index = Math.floor(durations.length * 0.95);

    return {
      count: filtered.length,
      avg: Number((sum / filtered.length).toFixed(2)),
      min: Number(durations[0].toFixed(2)),
      max: Number(durations[durations.length - 1].toFixed(2)),
      p95: Number(durations[p95Index].toFixed(2)),
    };
  }

  // Statistiques par op├®ration
  getStatsByOperation() {
    const grouped = new Map<string, number[]>();
    for (const m of this.metrics) {
      if (!grouped.has(m.name)) grouped.set(m.name, []);
      grouped.get(m.name)!.push(m.duration);
    }

    const result: Record<string, ReturnType<typeof this.getStats>> = {};
    for (const [name] of grouped) {
      result[name] = this.getStats(name);
    }
    return result;
  }

  getRecentMetrics(limit = 50) {
    return this.metrics.slice(-limit);
  }

  reset(): void {
    this.metrics = [];
  }
}

