// =============================================
// Request Auth & Data Scoping
// R├®sout l'utilisateur courant (JWT secondaire OU session LinkedIn admin)
// et fournit le p├®rim├¿tre de donn├®es (user_id) qu'il peut voir/modifier.
// =============================================

import { NextRequest } from "next/server";
import { query } from "./db";
import { verifyToken } from "./auth";

export interface RequestUser {
  userId: number;
  role: "admin" | "user";
  adminId: number | null;
  name: string;
}

// ---------------------------------------------
// Auto-migration : colonnes de propri├®t├® user_id
// Idempotent ÔÇö peut ├¬tre appel├® ├á chaque requ├¬te.
// ---------------------------------------------
let ownershipReady = false;
export async function ensureOwnershipColumns(): Promise<void> {
  if (ownershipReady) return;
  try {
    await query(`ALTER TABLE campaigns ADD COLUMN IF NOT EXISTS user_id INTEGER REFERENCES users(id) ON DELETE SET NULL`);
    await query(`ALTER TABLE prospects ADD COLUMN IF NOT EXISTS user_id INTEGER REFERENCES users(id) ON DELETE SET NULL`);
    await query(`ALTER TABLE messages  ADD COLUMN IF NOT EXISTS user_id INTEGER REFERENCES users(id) ON DELETE SET NULL`);
    await query(`ALTER TABLE agent_chat_history ADD COLUMN IF NOT EXISTS user_id INTEGER`);
    await query(`ALTER TABLE linkedin_actions_queue ADD COLUMN IF NOT EXISTS user_id INTEGER REFERENCES users(id) ON DELETE SET NULL`);
    await query(`CREATE INDEX IF NOT EXISTS idx_actions_user ON linkedin_actions_queue(user_id)`);
    await query(`CREATE INDEX IF NOT EXISTS idx_campaigns_user ON campaigns(user_id)`);
    await query(`CREATE INDEX IF NOT EXISTS idx_prospects_user ON prospects(user_id)`);
    await query(`CREATE INDEX IF NOT EXISTS idx_messages_user  ON messages(user_id)`);
    ownershipReady = true;
  } catch (e) {
    // Non-fatal : on log mais on ne bloque pas la requ├¬te
    console.error("ensureOwnershipColumns error (non-fatal):", e);
  }
}

// ---------------------------------------------
// R├®sout l'utilisateur courant ├á partir de la requ├¬te.
// 1. Bearer JWT  -> utilisateur secondaire (role=user)
// 2. Sinon       -> admin via session LinkedIn (un seul admin)
// ---------------------------------------------
export async function getRequestUser(request: NextRequest): Promise<RequestUser | null> {
  // 1. JWT (utilisateurs secondaires)
  const authHeader = request.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const payload = await verifyToken(authHeader.slice(7));
    if (payload && payload.userId) {
      // V├®rifier que le compte est toujours actif
      const check = await query(
        `SELECT id, name, role, admin_id, is_active FROM users WHERE id = $1`,
        [payload.userId]
      );
      const row = check.rows[0];
      if (row && row.is_active !== false) {
        return {
          userId: row.id,
          role: row.role === "admin" ? "admin" : "user",
          adminId: row.admin_id ?? null,
          name: row.name,
        };
      }
      return null;
    }
  }

  // 2. Fallback : admin via session LinkedIn
  const admin = await query(
    `SELECT id, name FROM users WHERE role = 'admin' ORDER BY id ASC LIMIT 1`
  );
  if (admin.rows.length > 0) {
    return {
      userId: admin.rows[0].id,
      role: "admin",
      adminId: null,
      name: admin.rows[0].name,
    };
  }

  return null;
}

// ---------------------------------------------
// Liste des user_id que le requester peut VOIR.
// - user  -> uniquement lui-m├¬me
// - admin -> lui-m├¬me + tous ses membres d'├®quipe
// ---------------------------------------------
export async function getScopeUserIds(user: RequestUser): Promise<number[]> {
  if (user.role === "admin") {
    const r = await query(
      `SELECT id FROM users WHERE id = $1 OR admin_id = $1`,
      [user.userId]
    );
    return r.rows.map((row) => row.id as number);
  }
  return [user.userId];
}

// ---------------------------------------------
// Construit une clause WHERE de scope sur une colonne user_id.
// Retourne { clause, params } ├á ins├®rer dans une requ├¬te SQL.
// startIndex = num├®ro du premier placeholder ($N).
//
// - admin : (col = ANY($N) OR col IS NULL)   (inclut les donn├®es legacy)
// - user  : col = $N                         (strict)
// ---------------------------------------------
export async function buildScopeClause(
  user: RequestUser,
  column: string,
  startIndex: number
): Promise<{ clause: string; params: any[]; nextIndex: number }> {
  if (user.role === "admin") {
    const ids = await getScopeUserIds(user);
    return {
      clause: `(${column} = ANY($${startIndex}) OR ${column} IS NULL)`,
      params: [ids],
      nextIndex: startIndex + 1,
    };
  }
  return {
    clause: `${column} = $${startIndex}`,
    params: [user.userId],
    nextIndex: startIndex + 1,
  };
}

// =============================================
// Security Utilities
// Chiffrement, validation, et sanitization
// =============================================

import crypto from "crypto";

// =============================================
// 1. ENCRYPTION (AES-256-GCM)
// =============================================
const ALGORITHM = "aes-256-gcm";
const IV_LENGTH = 16;
const AUTH_TAG_LENGTH = 16;

function getEncryptionKey(): Buffer {
  const key = process.env.ENCRYPTION_KEY;
  if (!key || key.length < 32) {
    // Fallback dev key ÔÇö DOIT ├¬tre d├®fini en production via .env.local
    return crypto
      .createHash("sha256")
      .update(key || "linkedin-agent-default-dev-key-change-in-prod")
      .digest();
  }
  return Buffer.from(key.slice(0, 32), "utf-8");
}

// Chiffrer une cha├«ne sensible (tokens API, credentials, etc.)
export function encrypt(plaintext: string): string {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, getEncryptionKey(), iv);
  const encrypted = Buffer.concat([
    cipher.update(plaintext, "utf-8"),
    cipher.final(),
  ]);
  const authTag = cipher.getAuthTag();
  // Format: iv:authTag:encrypted (tous en hex)
  return `${iv.toString("hex")}:${authTag.toString("hex")}:${encrypted.toString("hex")}`;
}

// D├®chiffrer une cha├«ne chiffr├®e
export function decrypt(ciphertext: string): string {
  const parts = ciphertext.split(":");
  if (parts.length !== 3) throw new Error("Invalid ciphertext format");
  const [ivHex, authTagHex, encryptedHex] = parts;
  const iv = Buffer.from(ivHex, "hex");
  const authTag = Buffer.from(authTagHex, "hex");
  const encrypted = Buffer.from(encryptedHex, "hex");
  const decipher = crypto.createDecipheriv(ALGORITHM, getEncryptionKey(), iv);
  decipher.setAuthTag(authTag);
  const decrypted = Buffer.concat([
    decipher.update(encrypted),
    decipher.final(),
  ]);
  return decrypted.toString("utf-8");
}

// =============================================
// 2. INPUT SANITIZATION (XSS prevention)
// =============================================
export function sanitizeHtml(input: string): string {
  if (typeof input !== "string") return "";
  return input
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#x27;")
    .replace(/\//g, "&#x2F;");
}

// Supprimer les caract├¿res dangereux pour SQL (en compl├®ment des requ├¬tes param├®tr├®es)
export function sanitizeSqlIdentifier(input: string): string {
  if (typeof input !== "string") return "";
  // Autoriser uniquement alphanum├®riques + underscore
  return input.replace(/[^a-zA-Z0-9_]/g, "");
}

// =============================================
// 3. INPUT VALIDATION
// =============================================
export const validators = {
  email: (v: string): boolean =>
    typeof v === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v),

  linkedinUrl: (v: string): boolean =>
    typeof v === "string" &&
    /^https:\/\/(www\.)?linkedin\.com\/in\/[a-zA-Z0-9\-_%]+\/?$/i.test(v),

  url: (v: string): boolean => {
    try {
      const u = new URL(v);
      return u.protocol === "https:" || u.protocol === "http:";
    } catch {
      return false;
    }
  },

  positiveInt: (v: any): boolean =>
    Number.isInteger(Number(v)) && Number(v) >= 0,

  // V├®rifier qu'une valeur est dans une whitelist (anti-injection)
  enum: (v: any, allowed: string[]): boolean =>
    typeof v === "string" && allowed.includes(v),

  // Longueur max pour ├®viter les attaques DoS
  maxLength: (v: string, max: number): boolean =>
    typeof v === "string" && v.length <= max,

  // Pas de scripts dans les cha├«nes
  noScript: (v: string): boolean =>
    typeof v === "string" &&
    !/<script|javascript:|on\w+\s*=/i.test(v),
};

// Valider un objet selon un sch├®ma
export function validate(
  data: Record<string, any>,
  schema: Record<string, (v: any) => boolean>
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  for (const [field, check] of Object.entries(schema)) {
    if (!check(data[field])) {
      errors.push(`Invalid field: ${field}`);
    }
  }
  return { valid: errors.length === 0, errors };
}

// =============================================
// 4. RATE LIMITING (par IP)
// =============================================
const apiRateLimits = new Map<string, { count: number; resetAt: number }>();

export function checkApiRateLimit(
  identifier: string,
  maxRequests = 100,
  windowMs = 60000
): { allowed: boolean; remaining: number; resetAt: number } {
  const now = Date.now();
  const entry = apiRateLimits.get(identifier);

  if (!entry || now > entry.resetAt) {
    apiRateLimits.set(identifier, { count: 1, resetAt: now + windowMs });
    return { allowed: true, remaining: maxRequests - 1, resetAt: now + windowMs };
  }

  if (entry.count >= maxRequests) {
    return { allowed: false, remaining: 0, resetAt: entry.resetAt };
  }

  entry.count++;
  return {
    allowed: true,
    remaining: maxRequests - entry.count,
    resetAt: entry.resetAt,
  };
}

// Cleanup automatique des entr├®es expir├®es
if (typeof setInterval !== "undefined") {
  setInterval(() => {
    const now = Date.now();
    for (const [key, entry] of apiRateLimits.entries()) {
      if (now > entry.resetAt) apiRateLimits.delete(key);
    }
  }, 5 * 60 * 1000);
}

// =============================================
// 5. CSRF / Origin validation
// =============================================
export function isAllowedOrigin(origin: string | null): boolean {
  if (!origin) return false;
  const allowed = [
    "http://localhost:3000",
    "http://localhost:3001",
    "chrome-extension://",
    process.env.NEXT_PUBLIC_APP_URL || "",
  ].filter(Boolean);
  return allowed.some((a) => origin.startsWith(a));
}

// =============================================
// 6. SECURE HASH (pour comparer des donn├®es sensibles)
// =============================================
export function hash(input: string): string {
  return crypto.createHash("sha256").update(input).digest("hex");
}

// Constant-time comparison pour ├®viter les timing attacks
export function safeCompare(a: string, b: string): boolean {
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
}

