  role?: string;
  location?: string;
  industry?: string;
  company_size?: string;
  network?: string;
}): string {
  const base = "https://www.linkedin.com/search/results/people/";
  const searchParams = new URLSearchParams();
  
  // Combiner keywords + role dans les mots-cl├®s (plus flexible que le filtre title= qui est trop restrictif)
  const keywordParts: string[] = [];
  if (params.keywords) keywordParts.push(params.keywords);
  if (params.role && params.role !== params.keywords) keywordParts.push(params.role);
  if (keywordParts.length > 0) searchParams.set("keywords", keywordParts.join(" "));
  
  // Note: geoUrn n├®cessite un ID LinkedIn num├®rique, pas un nom de ville
  // On l'ajoute dans les keywords si c'est un texte libre
  if (params.location) {
    // Si c'est un texte (pas un URN), l'ajouter aux keywords
    if (/^\d+$/.test(params.location)) {
      searchParams.set("geoUrn", params.location);
    } else {
      // Ajouter la localisation dans les keywords pour filtrage souple
      const currentKw = searchParams.get("keywords") || "";
      searchParams.set("keywords", `${currentKw} ${params.location}`.trim());
    }
  }
  
  // Filtre r├®seau: F=1er degr├®, S=2e degr├®, O=3e degr├®+
  if (params.network) searchParams.set("network", JSON.stringify([params.network]));
  
  return `${base}?${searchParams.toString()}`;
}

// TOOL: Lancer la v├®rification des connexions LinkedIn via l'extension Chrome
// Cr├®e les actions check_connection et retourne les IDs ÔÇö appeler get_connection_results ensuite
export const checkNetworkConnectionsTool = new DynamicStructuredTool({
  name: "check_network_connections",
  description: "Lance la v├®rification des connexions LinkedIn pour une liste de prospects via l'extension Chrome. Cr├®e les t├óches de v├®rification et retourne un check_id. Appeler ensuite get_connection_results avec ce check_id pour obtenir les r├®sultats (attendre ~15-20 secondes par prospect).",
  schema: z.object({
    prospect_names: z.array(z.string()).describe("Liste des noms de prospects ├á v├®rifier"),
    prospect_urls: z.array(z.string()).describe("Liste des URLs LinkedIn (m├¬me ordre que prospect_names)"),
  }),
  func: async ({ prospect_names, prospect_urls }) => {
    try {
      if (!prospect_urls || prospect_urls.length !== prospect_names.length) {
        return JSON.stringify({ success: false, error: "prospect_urls doit avoir le m├¬me nombre d'├®l├®ments que prospect_names." });
      }

      const normalizeUrl = (url: string) =>
        url.replace(/^https?:\/\/((?!www\.))(linkedin\.com)/i, "https://www.$2");

      const actionIds: number[] = [];
      for (let i = 0; i < prospect_names.length; i++) {
        const r = await insertLinkedInAction({
          action_type: 'check_connection',
          target_url: normalizeUrl(prospect_urls[i]),
          target_name: prospect_names[i],
          payload: { check_only: true },
          status: 'approved',
        });
        actionIds.push(r);
      }

      const estimatedSeconds = prospect_names.length * 20;
      return JSON.stringify({
        success: true,
        check_id: actionIds.join(","),
        action_ids: actionIds,
        total: prospect_names.length,
        message: `Ô£à V├®rification lanc├®e pour ${prospect_names.length} prospect(s). L'extension Chrome visite leurs profils. Attends ~${estimatedSeconds} secondes puis appelle get_connection_results avec check_id="${actionIds.join(",")}" pour voir les r├®sultats.`,
      });
    } catch (error) {
      return JSON.stringify({ success: false, error: error instanceof Error ? error.message : "Erreur" });
    }
  },
});

// TOOL: R├®cup├®rer les r├®sultats de v├®rification des connexions LinkedIn
export const getConnectionResultsTool = new DynamicStructuredTool({
  name: "get_connection_results",
  description: "R├®cup├¿re les r├®sultats de la v├®rification des connexions LinkedIn lanc├®e par check_network_connections. Appeler avec le check_id retourn├®. Si les r├®sultats ne sont pas encore pr├¬ts, attendre quelques secondes et r├®essayer.",
  schema: z.object({
    check_id: z.string().describe("L'identifiant retourn├® par check_network_connections (IDs s├®par├®s par virgule)"),
  }),
  func: async ({ check_id }) => {
    try {
      const actionIds = check_id.split(",").map((id: string) => parseInt(id.trim())).filter((id: number) => !isNaN(id));
      if (actionIds.length === 0) {
        return JSON.stringify({ success: false, error: "check_id invalide." });
      }

      const rows = await pool.query(
        `SELECT id, target_name, target_url, result, status FROM linkedin_actions_queue WHERE id = ANY($1)`,
        [actionIds]
      );

      const pending = rows.rows.filter((r: { status: string }) => r.status === "approved" || r.status === "processing");
      if (pending.length > 0) {
        return JSON.stringify({
          success: true,
          ready: false,
          pending_count: pending.length,
          total: actionIds.length,
          message: `ÔÅ│ ${pending.length}/${actionIds.length} v├®rification(s) encore en cours. R├®essaie dans 15 secondes.`,
        });
      }

      const inNetwork: Array<{ name: string; url: string }> = [];
      const notInNetwork: Array<{ name: string; url: string; reason: string }> = [];

      for (const row of rows.rows) {
        const res = typeof row.result === "string" ? JSON.parse(row.result || "{}") : (row.result || {});
        const degree = res.degree ?? 0;
        const connected = res.connected ?? (degree === 1);

        if (connected || degree === 1) {
          inNetwork.push({ name: row.target_name, url: row.target_url });
        } else if (row.status === "failed") {
          notInNetwork.push({ name: row.target_name, url: row.target_url, reason: "V├®rification ├®chou├®e ÔÇö profil inaccessible" });
        } else {
          notInNetwork.push({
            name: row.target_name,
            url: row.target_url,
            reason: degree === 0 ? "Degr├® non d├®termin├®" : `${degree}e degr├® ÔÇö pas encore connect├®`,
          });
        }
      }

      return JSON.stringify({
        success: true,
        ready: true,
        in_network: inNetwork,
        in_network_count: inNetwork.length,
        not_in_network: notInNetwork,
        not_in_network_count: notInNetwork.length,
        summary: `Ô£à ${inNetwork.length} prospect(s) dans votre r├®seau (message possible) : ${inNetwork.map(p => p.name).join(", ") || "aucun"}.\nÔØî ${notInNetwork.length} prospect(s) hors r├®seau (message impossible) : ${notInNetwork.map(p => `${p.name} (${p.reason})`).join(", ") || "aucun"}.`,
        can_message: inNetwork,
        cannot_message: notInNetwork,
      });
    } catch (error) {
      return JSON.stringify({ success: false, error: error instanceof Error ? error.message : "Erreur" });
    }
  },
});

